+    [Test]
+    procedure ICNavigateFromHandledOutboxSalesCreditMemo()
+    var
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesCrMemoHeader: Record "Sales Cr.Memo Header";
+        HandledICOutboxTrans: Record "Handled IC Outbox Trans.";
+        ICOutboxTransaction: Record "IC Outbox Transaction";
+        ICInboxOutboxMgt: Codeunit ICInboxOutboxMgt;
+        HandledICOutboxTransactions: TestPage "Handled IC Outbox Transactions";
+        PostedSalesCreditMemo: TestPage "Posted Sales Credit Memo";
+        ICPartnerCode: Code[20];
+        PostedDocNo: Code[20];
+    begin
+        // [FEATURE] [Sales] [Credit Memo]
+        // [SCENARIO 530215] Navigate to Posted Sales Credit Memo from Handled IC Outbox Transactions using Go to Document action
+        Initialize();
+        LibraryApplicationArea.EnableEssentialSetup();
+        CleanupIC(false, true, true, false);
+
+        // [GIVEN] A customer with an IC Partner Code
+        ICPartnerCode := CreateICPartnerWithInbox();
+        CreateCustomerWithICPartner(Customer, ICPartnerCode);
+        UpdateICPartnerCodeOnCompanyInfo(ICPartnerCode);
+
+        // [GIVEN] A Sales Credit Memo posted for the IC customer
+        LibrarySales.CreateSalesCreditMemoForCustomerNo(SalesHeader, Customer."No.");
+        PostedDocNo := LibrarySales.PostSalesDocument(SalesHeader, true, true);
+
+        // [GIVEN] The Sales Credit Memo IC transaction is sent and moved to Handled IC Outbox
+        ICOutboxTransaction.SetRange("Document Type", ICOutboxTransaction."Document Type"::"Credit Memo");
+        ICOutboxTransaction.SetRange("IC Source Type", ICOutboxTransaction."IC Source Type"::"Sales Document");
+        ICOutboxTransaction.SetRange("Document No.", PostedDocNo);
+        if ICOutboxTransaction.FindFirst() then
+            ICInboxOutboxMgt.SendToExternalPartner(ICOutboxTransaction);
+        Commit();
+
+        // [WHEN] Opening Handled IC Outbox Transactions and invoking Go to Document
+        HandledICOutboxTrans.SetRange("Document Type", HandledICOutboxTrans."Document Type"::"Credit Memo");
+        HandledICOutboxTrans.SetRange("Source Type", HandledICOutboxTrans."Source Type"::"Sales Document");
+        HandledICOutboxTrans.SetRange("Document No.", PostedDocNo);
+        HandledICOutboxTrans.FindFirst();
+
+        HandledICOutboxTransactions.OpenEdit();
+        HandledICOutboxTransactions.GoToRecord(HandledICOutboxTrans);
+        PostedSalesCreditMemo.Trap();
+        HandledICOutboxTransactions.GoToDocument.Invoke();
+
+        // [THEN] The Posted Sales Credit Memo page should open with the correct document
+        SalesCrMemoHeader.Get(PostedDocNo);
+        PostedSalesCreditMemo."No.".AssertEquals(SalesCrMemoHeader."No.");
+
+        // Cleanup
+        CleanupIC(false, true, true, false);
+    end;
+
     [Test]
