@@ -2604,6 +2604,104 @@ codeunit 137055 "SCM Warehouse Pick"
         exit(-PurchaseLine."Return Qty. to Ship");
     end;

+    [Test]
+    [Scope('OnPrem')]
+    procedure ChangeQtyOnTakeLineUpdatesCorrectPlaceLineForProdConsumption()
+    var
+        Item: Record Item;
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        TakeLine1: Record "Warehouse Activity Line";
+        PlaceLine1: Record "Warehouse Activity Line";
+        TakeLine2: Record "Warehouse Activity Line";
+        PlaceLine2: Record "Warehouse Activity Line";
+        Location: Record Location;
+        WarehouseEmployee: Record "Warehouse Employee";
+        Bin1: Record Bin;
+        Bin2: Record Bin;
+        ToBin: Record Bin;
+        WarehousePick: TestPage "Warehouse Pick";
+        OriginalQty: Decimal;
+        NewQty: Decimal;
+    begin
+        // [FEATURE] [Warehouse Pick] [Production Consumption] [Overpick]
+        // [SCENARIO] When manually changing quantity on a Take line in a Warehouse Pick for Production Consumption,
+        // the correct corresponding Place line (the one immediately after the Take line) should be updated.
+
+        // [GIVEN] Location with Require Pick and Prod. Consump. Whse. Handling = Warehouse Pick (mandatory)
+        Initialize();
+        CreateLocationForProdConsumptionPick(Location, Bin1, Bin2, ToBin);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, false);
+
+        // [GIVEN] An Item with Allow Whse. Overpick enabled
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Allow Whse. Overpick", true);
+        Item.Modify(true);
+
+        OriginalQty := 900;
+        NewQty := 400;
+
+        // [GIVEN] Create a Warehouse Pick with 2 Take/Place pairs for the same item
+        // Line structure: Take1(Line 10000), Place1(Line 20000), Take2(Line 30000), Place2(Line 40000)
+        LibraryWarehouse.CreateWarehouseActivityHeader(WarehouseActivityHeader, WarehouseActivityHeader.Type::Pick, Location.Code);
+        CreateWhseActivityLineForProdConsumption(TakeLine1, WarehouseActivityHeader, Item."No.", Location.Code, Bin1.Code, TakeLine1."Action Type"::Take, 10000, OriginalQty);
+        CreateWhseActivityLineForProdConsumption(PlaceLine1, WarehouseActivityHeader, Item."No.", Location.Code, ToBin.Code, PlaceLine1."Action Type"::Place, 20000, OriginalQty);
+        CreateWhseActivityLineForProdConsumption(TakeLine2, WarehouseActivityHeader, Item."No.", Location.Code, Bin2.Code, TakeLine2."Action Type"::Take, 30000, OriginalQty);
+        CreateWhseActivityLineForProdConsumption(PlaceLine2, WarehouseActivityHeader, Item."No.", Location.Code, ToBin.Code, PlaceLine2."Action Type"::Place, 40000, OriginalQty);
+
+        // [WHEN] Change the quantity on the second Take line (Line 30000) from 900 to 400 via UI
+        WarehousePick.OpenEdit();
+        WarehousePick.Filter.SetFilter("No.", WarehouseActivityHeader."No.");
+        WarehousePick.WhseActivityLines.Filter.SetFilter("Line No.", Format(TakeLine2."Line No."));
+        WarehousePick.WhseActivityLines.Quantity.SetValue(NewQty);
+        WarehousePick.Close();
+
+        // [THEN] The second Place line (Line 40000) should be updated to 400 (not the first Place line)
+        PlaceLine2.Get(PlaceLine2."Activity Type", PlaceLine2."No.", PlaceLine2."Line No.");
+        Assert.AreEqual(NewQty, PlaceLine2.Quantity, 'The second Place line should have quantity updated to match the Take line.');
+
+        // [THEN] The first Place line (Line 20000) should still have the original quantity 900
+        PlaceLine1.Get(PlaceLine1."Activity Type", PlaceLine1."No.", PlaceLine1."Line No.");
+        Assert.AreEqual(OriginalQty, PlaceLine1.Quantity, 'The first Place line should retain its original quantity.');
+    end;
+
+    local procedure CreateLocationForProdConsumptionPick(var Location: Record Location; var Bin1: Record Bin; var Bin2: Record Bin; var ToBin: Record Bin)
+    begin
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+        Location.Validate("Bin Mandatory", true);
+        Location.Validate("Require Pick", true);
+        Location.Validate("Prod. Consump. Whse. Handling", "Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)");
+        Location.Modify(true);
+
+        LibraryWarehouse.CreateBin(Bin1, Location.Code, 'S-01-01', '', '');
+        LibraryWarehouse.CreateBin(Bin2, Location.Code, 'S-01-02', '', '');
+        LibraryWarehouse.CreateBin(ToBin, Location.Code, 'TO-PROD', '', '');
+
+        Location.Validate("To-Production Bin Code", ToBin.Code);
+        Location.Modify(true);
+    end;
+
+    local procedure CreateWhseActivityLineForProdConsumption(var WarehouseActivityLine: Record "Warehouse Activity Line"; WarehouseActivityHeader: Record "Warehouse Activity Header"; ItemNo: Code[20]; LocationCode: Code[10]; BinCode: Code[20]; ActionType: Enum "Warehouse Action Type"; LineNo: Integer; Qty: Decimal)
+    begin
+        WarehouseActivityLine.Init();
+        WarehouseActivityLine."Activity Type" := WarehouseActivityHeader.Type;
+        WarehouseActivityLine."No." := WarehouseActivityHeader."No.";
+        WarehouseActivityLine."Line No." := LineNo;
+        WarehouseActivityLine."Location Code" := LocationCode;
+        WarehouseActivityLine."Item No." := ItemNo;
+        WarehouseActivityLine."Action Type" := ActionType;
+        WarehouseActivityLine."Bin Code" := BinCode;
+        WarehouseActivityLine."Source Type" := Database::"Prod. Order Component";
+        WarehouseActivityLine."Source Document" := WarehouseActivityLine."Source Document"::"Prod. Consumption";
+        WarehouseActivityLine."Source No." := 'PO-TEST-001';
+        WarehouseActivityLine."Source Line No." := 10000;
+        WarehouseActivityLine."Qty. per Unit of Measure" := 1;
+        WarehouseActivityLine.Quantity := Qty;
+        WarehouseActivityLine."Qty. (Base)" := Qty;
+        WarehouseActivityLine."Qty. Outstanding" := Qty;
+        WarehouseActivityLine."Qty. Outstanding (Base)" := Qty;
+        WarehouseActivityLine.Insert();
+    end;
+
