     procedure ReservationPageHandler(var Reservation: TestPage Reservation)

diff --git a/App/Apps/W1/AutomaticAccountCodes/test/src/AACAutoAccGroupPosting.Codeunit.al b/App/Apps/W1/AutomaticAccountCodes/test/src/AACAutoAccGroupPosting.Codeunit.al
index 6626b2b4..21f9f090 100644
--- a/App/Apps/W1/AutomaticAccountCodes/test/src/AACAutoAccGroupPosting.Codeunit.al
+++ b/App/Apps/W1/AutomaticAccountCodes/test/src/AACAutoAccGroupPosting.Codeunit.al
@@ -29,6 +29,98 @@ codeunit 139598 "AAC Auto. Acc. Group Posting"

         WrongAmountGLEntriesErr: Label 'Wrong Amount in G/L Entry.';

+    [Test]
+    [Scope('OnPrem')]
+    procedure PostGenJournalWithCurrencyAndRoundingLCYAdjustment()
+    var
+        AutomaticAccountHeader: Record "Automatic Account Header";
+        AutomaticAccountLine: Record "Automatic Account Line";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GenJournalLine: Record "Gen. Journal Line";
+        GenJournalLine2: Record "Gen. Journal Line";
+        GLEntry: Record "G/L Entry";
+        GLAccountNo1: Code[20];
+        GLAccountNo2: Code[20];
+        GLAccountNo3: Code[20];
+        AutoAccGroupNo: Code[10];
+        CurrencyCode: Code[10];
+        AmountFCY: Decimal;
+    begin
+        // [FEATURE] [Currency] [Rounding]
+        // [SCENARIO] Posting Gen. Journal with currency and automatic account group where 50% allocation causes LCY rounding issue
+        // When Amount (LCY) is an odd amount that doesn't divide evenly by 2, the system should adjust the last line's Amount (LCY)
+        // to prevent "Inconsistency" error in G/L Entry table
+
+        // [GIVEN] G/L Setup with Amount Rounding Precision = 0.01
+        Initialize();
+
+        // [GIVEN] Currency "EUR" with exchange rate that causes rounding issue: Amount 480 EUR = 5266.67 LCY
+        // Exchange rate: 1 EUR = 10.97223 LCY (approximately)
+        CurrencyCode := LibraryERM.CreateCurrencyWithRoundingPrecision(0.01);
+        LibraryERM.CreateExchangeRate(CurrencyCode, WorkDate(), 10.97222916666667, 10.97222916666667);
+
+        // [GIVEN] Automatic Acc. Group "AAG" with three lines simulating the repro scenario:
+        // Line1: "G/L Account No." = "ACC1", "Allocation %" = 50
+        // Line2: "G/L Account No." = "ACC2", "Allocation %" = 50
+        // Line3: "G/L Account No." = "ACC3", "Allocation %" = -100 (balancing line)
+        LibraryAAC.CreateAutomaticAccountHeader(AutomaticAccountHeader);
+        AutoAccGroupNo := AutomaticAccountHeader."No.";
+
+        GLAccountNo1 := LibraryERM.CreateGLAccountNo();
+        GLAccountNo2 := LibraryERM.CreateGLAccountNo();
+        GLAccountNo3 := LibraryERM.CreateGLAccountNo();
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo1);
+        AutomaticAccountLine.Validate("Allocation %", 50);
+        AutomaticAccountLine.Modify(true);
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo2);
+        AutomaticAccountLine.Validate("Allocation %", 50);
+        AutomaticAccountLine.Modify(true);
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo3);
+        AutomaticAccountLine.Validate("Allocation %", -100);
+        AutomaticAccountLine.Modify(true);
+
+        // [GIVEN] General Journal with Currency and two lines:
+        // Line1: Amount = 480 EUR, "Automatic Account Group" = "AAG"
+        // Line2: Amount = -480 EUR (balancing line, no automatic account group)
+        // Amount (LCY) = 480 * 10.97222916666667 = 5266.67 (rounded)
+        AmountFCY := 480;
+
+        LibraryERM.CreateGenJournalBatch(GenJournalBatch, LibraryERM.SelectGenJnlTemplate());
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::" ", GenJournalLine."Account Type"::"G/L Account",
+            LibraryERM.CreateGLAccountNo(), AmountFCY);
+        GenJournalLine.Validate("Currency Code", CurrencyCode);
+        GenJournalLine.Validate("Automatic Account Group", AutoAccGroupNo);
+        GenJournalLine.Modify(true);
+
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine2, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine2."Document Type"::" ", GenJournalLine2."Account Type"::"G/L Account",
+            LibraryERM.CreateGLAccountNo(), -AmountFCY);
+        GenJournalLine2.Validate("Document No.", GenJournalLine."Document No.");
+        GenJournalLine2.Validate("Currency Code", CurrencyCode);
+        GenJournalLine2.Modify(true);
+
+        // [WHEN] Post General Journal
+        // Without the fix, this would fail with "The transaction cannot be completed because it will cause inconsistencies in the G/L Entry table"
+        // because 5266.67 / 2 = 2633.335 rounds to 2633.34, and 2633.34 * 2 = 5266.68 <> 5266.67
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [THEN] G/L Entries are created without error
+        // [THEN] The sum of amounts for all automatic account lines equals zero (balanced)
+        GLEntry.SetRange("Document No.", GenJournalLine."Document No.");
+        GLEntry.SetFilter("G/L Account No.", '%1|%2|%3', GLAccountNo1, GLAccountNo2, GLAccountNo3);
+        GLEntry.CalcSums(Amount);
+        Assert.AreEqual(0, GLEntry.Amount, 'Sum of automatic account G/L entries should be zero');
+    end;
+
     [Test]
     [Scope('OnPrem')]
     procedure CopyDimensionsFromAccGroup()

