@@ -3924,5 +3924,94 @@ codeunit 136305 "Job Journal"
         ContactList.GoToKey(LibraryVariableStorage.DequeueText());
         ContactList.OK().Invoke();
     end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RecurringJobJournalVariableMethodPreservesUnitCostAndPrice()
+    var
+        JobJournalTemplate: Record "Job Journal Template";
+        JobJournalBatch: Record "Job Journal Batch";
+        JobJournalLine: Record "Job Journal Line";
+        Resource: Record Resource;
+        JobTask: Record "Job Task";
+        OriginalUnitCost: Decimal;
+        OriginalUnitPrice: Decimal;
+    begin
+        // [FEATURE] [Recurring Job Journal] [Variable Method]
+        // [SCENARIO] When posting a recurring job journal line with Variable method, Unit Cost and Unit Price should be preserved for the next posting.
+
+        // [GIVEN] A recurring job journal template with batch
+        Initialize();
+        CreateRecurringJobJournalTemplateAndBatch(JobJournalTemplate, JobJournalBatch);
+
+        // [GIVEN] A Job with Job Task and Resource
+        CreateJobWithJobTask(JobTask);
+        LibraryResource.CreateResourceNew(Resource);
+        Resource.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        Resource.Validate("Unit Price", LibraryRandom.RandDecInRange(50, 200, 2));
+        Resource.Modify(true);
+
+        // [GIVEN] A recurring job journal line with Variable recurring method
+        CreateRecurringJobJournalLine(
+            JobJournalLine,
+            JobJournalTemplate.Name,
+            JobJournalBatch.Name,
+            JobTask,
+            Resource."No."
+        );
+        OriginalUnitCost := JobJournalLine."Unit Cost";
+        OriginalUnitPrice := JobJournalLine."Unit Price";
+
+        // [WHEN] Posting the recurring job journal batch
+        Codeunit.Run(Codeunit::"Job Jnl.-Post Batch", JobJournalLine);
+
+        // [THEN] The job journal line should still exist with preserved Unit Cost and Unit Price
+        JobJournalLine.SetRange("Journal Template Name", JobJournalTemplate.Name);
+        JobJournalLine.SetRange("Journal Batch Name", JobJournalBatch.Name);
+        JobJournalLine.FindFirst();
+
+        // [THEN] Quantity should be zero (as expected for Variable method)
+        JobJournalLine.TestField(Quantity, 0);
+
+        // [THEN] Unit Cost and Unit Price should be preserved for next posting
+        Assert.AreEqual(OriginalUnitCost, JobJournalLine."Unit Cost", 'Unit Cost should be preserved after posting recurring journal with Variable method');
+        Assert.AreEqual(OriginalUnitPrice, JobJournalLine."Unit Price", 'Unit Price should be preserved after posting recurring journal with Variable method');
+
+        // Tear Down
+        JobJournalTemplate.Delete(true);
+    end;
+
+    local procedure CreateRecurringJobJournalTemplateAndBatch(var JobJournalTemplate: Record "Job Journal Template"; var JobJournalBatch: Record "Job Journal Batch")
+    begin
+        JobJournalTemplate.Init();
+        JobJournalTemplate.Name := LibraryUtility.GenerateGUID();
+        JobJournalTemplate.Validate(Recurring, true);
+        JobJournalTemplate.Insert(true);
+
+        JobJournalBatch.Init();
+        JobJournalBatch."Journal Template Name" := JobJournalTemplate.Name;
+        JobJournalBatch.Name := LibraryUtility.GenerateGUID();
+        JobJournalBatch.Insert(true);
+    end;
+
+    local procedure CreateRecurringJobJournalLine(var JobJournalLine: Record "Job Journal Line"; TemplateName: Code[10]; BatchName: Code[10]; JobTask: Record "Job Task"; ResourceNo: Code[20])
+    begin
+        JobJournalLine.Init();
+        JobJournalLine."Journal Template Name" := TemplateName;
+        JobJournalLine."Journal Batch Name" := BatchName;
+        JobJournalLine."Line No." := 10000;
+        JobJournalLine.Insert(true);
+
+        JobJournalLine.Validate("Posting Date", WorkDate());
+        JobJournalLine.Validate("Document No.", LibraryUtility.GenerateGUID());
+        JobJournalLine.Validate("Job No.", JobTask."Job No.");
+        JobJournalLine.Validate("Job Task No.", JobTask."Job Task No.");
+        JobJournalLine.Validate(Type, JobJournalLine.Type::Resource);
+        JobJournalLine.Validate("No.", ResourceNo);
+        JobJournalLine.Validate(Quantity, LibraryRandom.RandIntInRange(1, 10));
+        JobJournalLine.Validate("Recurring Method", JobJournalLine."Recurring Method"::Variable);
+        JobJournalLine.Validate("Recurring Frequency", '<1M>');
+        JobJournalLine.Modify(true);
+    end;
 }

