+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure UndoTransShptAfterRevaluationOfAppliedInboundEntry()
+    var
+        Item: Record Item;
+        FromLocation: Record Location;
+        ToLocation: Record Location;
+        InTransitLocation: Record Location;
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        OriginalILENo: Integer;
+        OriginalUnitCost: Decimal;
+        RevaluedUnitCost: Decimal;
+        TotalCostAmount: Decimal;
+    begin
+        // [FEATURE] [Transfer] [Order] [Undo Shipment] [Revaluation]
+        // [SCENARIO] Undo Transfer Shipment after revaluation of the applied inbound entry should correctly propagate the revalued cost
+        Initialize();
+
+        // [GIVEN] Original unit cost = 10, Revalued unit cost = 12
+        OriginalUnitCost := 10;
+        RevaluedUnitCost := 12;
+
+        // [GIVEN] Create locations
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(FromLocation);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(ToLocation);
+        LibraryWarehouse.CreateInTransitLocation(InTransitLocation);
+
+        // [GIVEN] Create Item and post positive adjustment with unit cost = 10
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, Item."No.", FromLocation.Code, '', 1);
+        ItemJournalLine.Validate("Unit Cost", OriginalUnitCost);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] Find the original positive adjustment ILE
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::"Positive Adjmt.");
+        ItemLedgerEntry.FindFirst();
+        OriginalILENo := ItemLedgerEntry."Entry No.";
+
+        // [GIVEN] Create and post Transfer Shipment
+        LibraryInventory.CreateTransferHeader(TransferHeader, FromLocation.Code, ToLocation.Code, InTransitLocation.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", 1);
+        LibraryInventory.PostTransferHeader(TransferHeader, true, false);
+
+        // [GIVEN] Revalue the original positive adjustment ILE to unit cost = 12
+        LibraryInventory.CreateItemJournalBatchByType(ItemJournalBatch, ItemJournalBatch."Template Type"::Revaluation);
+        LibraryInventory.CreateItemJnlLineWithNoItem(
+            ItemJournalLine, ItemJournalBatch, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::" ");
+        ItemJournalLine.Validate("Value Entry Type", ItemJournalLine."Value Entry Type"::Revaluation);
+        ItemJournalLine.Validate("Item No.", Item."No.");
+        ItemJournalLine.Validate(Quantity, 1);
+        ItemJournalLine.Validate("Applies-to Entry", OriginalILENo);
+        ItemJournalLine.Validate("Unit Cost (Revalued)", RevaluedUnitCost);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] Adjust cost - Item Entries
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [WHEN] Undo the Transfer Shipment
+        LibraryInventory.UndoTransferShipments(TransferHeader."No.");
+
+        // [WHEN] Adjust cost - Item Entries again
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [THEN] The sum of Cost Amount (Actual) for all transfer-related ILEs should be zero
+        // This verifies that the undo shipment correctly uses the revalued cost
+        ItemLedgerEntry.Reset();
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Transfer);
+        ItemLedgerEntry.CalcSums("Cost Amount (Actual)");
+        TotalCostAmount := ItemLedgerEntry."Cost Amount (Actual)";
+
+        Assert.AreEqual(0, TotalCostAmount, 'Sum of Cost Amount (Actual) for Transfer ILEs should be zero after Undo Shipment with revaluation.');
+    end;
+
     [Test]
     [HandlerFunctions('CreateInvtPickRequestPageHandler,MessageHandler')]
     procedure S453705_PostingDirectTransferOrderviaInventoryPutAway()

