+    [Test]
+    [Scope('OnPrem')]
+    procedure QuantityPerPreservedWhenComponentItemUOMHasRoundingPrecisionOne()
+    var
+        ComponentItem: Record Item;
+        FinishedGoodsItem: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        QuantityPer: Decimal;
+    begin
+        // [FEATURE] [Manufacturing] [Production BOM] [Unit of Measure]
+        // [SCENARIO] When a component's Item UOM has 'Qty. Rounding Precision' = 1, and the Production BOM uses a fractional
+        // Quantity per value, the Prod. Order Component should preserve the fractional 'Quantity per' value instead of rounding to 0.
+
+        // [GIVEN] Create Component Item with Replenishment System = Purchase and Rounding Precision = 0.01
+        Initialize();
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Set 'Qty. Rounding Precision' = 1 on the Component Item's Base Unit of Measure
+        ItemUnitOfMeasure.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] Create Production BOM with the Component Item with fractional 'Quantity Per' = 0.09
+        QuantityPer := 0.09;
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QuantityPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Create Finished Goods Item with Replenishment System = Prod. Order, Rounding Precision = 1
+        LibraryInventory.CreateItem(FinishedGoodsItem);
+        FinishedGoodsItem.Validate("Replenishment System", FinishedGoodsItem."Replenishment System"::"Prod. Order");
+        FinishedGoodsItem.Validate("Rounding Precision", 1);
+        FinishedGoodsItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedGoodsItem.Modify(true);
+
+        // [WHEN] Create and Refresh Released Production Order for the Finished Goods Item with Quantity = 1
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, FinishedGoodsItem."No.", 1);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [THEN] Verify that Prod. Order Component has 'Quantity per' = 0.09 (not rounded to 0)
+        ProdOrderComponent.SetRange(Status, ProductionOrder.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+
+        Assert.AreEqual(
+            QuantityPer,
+            ProdOrderComponent."Quantity per",
+            'Quantity per should not be rounded to 0 when using fractional BOM quantity with Item UOM Qty. Rounding Precision = 1');
+
+        // [THEN] Verify that Expected Quantity is also calculated correctly (Quantity per * Prod Order Qty = 0.09 * 1 = 0.09)
+        Assert.AreEqual(
+            QuantityPer,
+            ProdOrderComponent."Expected Quantity",
+            'Expected Quantity should match the Quantity per for 1 unit of Finished Goods');
+    end;
+
