+codeunit 134989 "Reminder Level Comm. Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    local procedure Initialize()
+    begin
+        LibraryVariableStorage.Clear();
+        if IsInitialized then
+            exit;
+
+        IsInitialized := true;
+        Commit();
+    end;
+
+    [Test]
+    procedure SelectLanguageAndTextReadsFromDatabaseWithStalePageRecord()
+    var
+        ReminderTerms: Record "Reminder Terms";
+        ReminderLevel: Record "Reminder Level";
+        StaleReminderLevel: Record "Reminder Level";
+        ReminderAttachmentText: Record "Reminder Attachment Text";
+        ReminderEmailText: Record "Reminder Email Text";
+        Language: Record Language;
+        ReminderLevelCommunicationPage: Page "Reminder Level Communication";
+        AttachmentTextId: Guid;
+        EmailTextId: Guid;
+        EmptyGuid: Guid;
+    begin
+        // [SCENARIO 1] Bug fix verification: When the page record has stale/empty values for 
+        // "Reminder Attachment Text" and "Reminder Email Text", but the database record has 
+        // valid IDs, the SelectLanguageAndText procedure should use the database values.
+        // 
+        // This reproduces the exact bug scenario:
+        // 1. User opens Reminder Level Communication page with no attachment texts
+        // 2. "Add text for language" action creates new GUIDs and updates the database
+        // 3. But the page's Rec variable still has empty GUIDs (stale)
+        // 4. SelectLanguageAndText is called and should read from database, not stale Rec
+        // 
+        // Before the fix: Error "A reminder attachment text cannot be created without an ID"
+        // After the fix: Works correctly by reading from database
+
+        // [GIVEN] A Reminder Terms with a Reminder Level (no attachment texts initially)
+        Initialize();
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+
+        // [GIVEN] Get a copy of the record before updating (simulating stale page Rec variable)
+        StaleReminderLevel := ReminderLevel;
+
+        // [GIVEN] Simulate what happens when "Add text for language" action updates the database
+        // The ReminderCommunication.SetDefaultContentForNewLanguage creates new GUIDs and saves them
+        AttachmentTextId := CreateGuid();
+        EmailTextId := CreateGuid();
+        ReminderLevel."Reminder Attachment Text" := AttachmentTextId;
+        ReminderLevel."Reminder Email Text" := EmailTextId;
+        ReminderLevel.Modify(true);
+
+        // Verify the stale record still has empty GUIDs (this is the bug condition)
+        Assert.AreEqual(EmptyGuid, StaleReminderLevel."Reminder Attachment Text", 
+            'Test setup: Stale record should have empty attachment text ID');
+        Assert.AreEqual(EmptyGuid, StaleReminderLevel."Reminder Email Text", 
+            'Test setup: Stale record should have empty email text ID');
+
+        // Get the first available language for testing
+        Language.FindFirst();
+
+        // [WHEN] SelectLanguageAndText is called with the stale record set on the page
+        // The page's Rec has empty GUIDs, but the database has valid GUIDs
+        ReminderLevelCommunicationPage.SetRecord(StaleReminderLevel);
+        ReminderLevelCommunicationPage.SelectLanguageAndText(Language.Code, true);
+
+        // [THEN] Attachment and email texts should be created using the database record's IDs
+        // The fix ensures ReminderLevel.Get() is called to read current values from database
+        ReminderAttachmentText.SetRange(Id, AttachmentTextId);
+        ReminderAttachmentText.SetRange("Language Code", Language.Code);
+        Assert.IsFalse(ReminderAttachmentText.IsEmpty(), 
+            'Reminder Attachment Text should be created with the database record ID, not the stale empty ID');
+
+        ReminderEmailText.SetRange(Id, EmailTextId);
+        ReminderEmailText.SetRange("Language Code", Language.Code);
+        Assert.IsFalse(ReminderEmailText.IsEmpty(), 
+            'Reminder Email Text should be created with the database record ID, not the stale empty ID');
+    end;
+
+    [Test]
+    procedure SelectLanguageAndTextCreatesNewTextsWithCorrectIds()
+    var
+        ReminderTerms: Record "Reminder Terms";
+        ReminderLevel: Record "Reminder Level";
+        ReminderAttachmentText: Record "Reminder Attachment Text";
+        ReminderEmailText: Record "Reminder Email Text";
+        Language: Record Language;
+        ReminderLevelCommunicationPage: Page "Reminder Level Communication";
+        AttachmentTextId: Guid;
+        EmailTextId: Guid;
+    begin
+        // [SCENARIO 2] Verify SelectLanguageAndText creates new attachment and email texts
+        // with the correct IDs when the Reminder Level already has valid IDs set.
+
+        // [GIVEN] A Reminder Terms with a Reminder Level that has attachment/email text IDs
+        Initialize();
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+
+        AttachmentTextId := CreateGuid();
+        EmailTextId := CreateGuid();
+        ReminderLevel."Reminder Attachment Text" := AttachmentTextId;
+        ReminderLevel."Reminder Email Text" := EmailTextId;
+        ReminderLevel.Modify(true);
+
+        // Get the first available language for testing
+        Language.FindFirst();
+
+        // [WHEN] SelectLanguageAndText is called with CreateNewEntry = true
+        ReminderLevelCommunicationPage.SetRecord(ReminderLevel);
+        ReminderLevelCommunicationPage.SelectLanguageAndText(Language.Code, true);
+
+        // [THEN] Attachment texts should be created with the correct IDs
+        ReminderAttachmentText.SetRange(Id, AttachmentTextId);
+        ReminderAttachmentText.SetRange("Language Code", Language.Code);
+        Assert.IsFalse(ReminderAttachmentText.IsEmpty(), 
+            'Reminder Attachment Text should be created for the specified language');
+
+        ReminderEmailText.SetRange(Id, EmailTextId);
+        ReminderEmailText.SetRange("Language Code", Language.Code);
+        Assert.IsFalse(ReminderEmailText.IsEmpty(), 
+            'Reminder Email Text should be created for the specified language');
+    end;
+}

