diff --git a/App/Layers/W1/Tests/SCM-Assembly/SCMAssemblyAvailabilityDueDateTest.Codeunit.al b/App/Layers/W1/Tests/SCM-Assembly/SCMAssemblyAvailabilityDueDateTest.Codeunit.al
new file mode 100644
index 00000000..f4f7a9bc
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM-Assembly/SCMAssemblyAvailabilityDueDateTest.Codeunit.al
@@ -0,0 +1,249 @@
+// ------------------------------------------------------------------------------------------------
