+namespace Microsoft.Assembly.Test;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Assembly.Document;
+using Microsoft.Inventory.BOM;
+using Microsoft.Inventory.Journal;
+
+codeunit 137913 "SCM Asm. Avail. Due Date Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Assembly] [SCM] [Availability Warning] [Due Date]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryAssembly: Codeunit "Library - Assembly";
+        NotificationLifecycleMgt: Codeunit "Notification Lifecycle Mgt.";
+        Initialized: Boolean;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Asm. Avail. Due Date Test");
+        if Initialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Asm. Avail. Due Date Test");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        Initialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Asm. Avail. Due Date Test");
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure AvailWarningConsidersDueDateNotFutureDemand()
+    var
+        ParentItem: Record Item;
+        ChildItem: Record Item;
+        AsmHeader1: Record "Assembly Header";
+        AsmHeader2: Record "Assembly Header";
+        AsmLine1: Record "Assembly Line";
+        AsmLine2: Record "Assembly Line";
+        QtyPerComponent: Decimal;
+        ComponentInventory: Decimal;
+        OrderQty1: Decimal;
+        OrderQty2: Decimal;
+        DueDate1: Date;
+        DueDate2: Date;
+    begin
+        // [SCENARIO] Availability Warning on Assembly Orders should consider Due Dates
+        // and not show warning when there is sufficient inventory for the order's due date,
+        // even if future orders would consume more than the available inventory.
+        Initialize();
+
+        // [GIVEN] An assembled item with one component (Qty Per = 2)
+        QtyPerComponent := 2;
+        CreateAssembledItem(ParentItem, ChildItem, QtyPerComponent);
+
+        // [GIVEN] 2 PCS of component in inventory (enough for 1 assembled item)
+        ComponentInventory := 2;
+        AddItemToInventory(ChildItem."No.", ComponentInventory);
+
+        // [GIVEN] Assembly Order #1 for 1 qty with Due Date = Today
+        OrderQty1 := 1;
+        DueDate1 := WorkDate();
+        CreateAssemblyOrder(AsmHeader1, ParentItem."No.", OrderQty1, DueDate1);
+        AsmLine1.SetRange("Document Type", AsmHeader1."Document Type");
+        AsmLine1.SetRange("Document No.", AsmHeader1."No.");
+        AsmLine1.SetRange(Type, AsmLine1.Type::Item);
+        AsmLine1.FindFirst();
+
+        // [GIVEN] Verify no availability warning for Order #1 (we have exactly 2 components needed)
+        Assert.IsFalse(AsmLine1."Avail. Warning",
+            'Expected no availability warning for Order #1 with sufficient inventory');
+
+        // [GIVEN] Assembly Order #2 for 3 qty with Due Date = 5 days later (needs 6 components)
+        OrderQty2 := 3;
+        DueDate2 := CalcDate('<+5D>', WorkDate());
+        CreateAssemblyOrder(AsmHeader2, ParentItem."No.", OrderQty2, DueDate2);
+        AsmLine2.SetRange("Document Type", AsmHeader2."Document Type");
+        AsmLine2.SetRange("Document No.", AsmHeader2."No.");
+        AsmLine2.SetRange(Type, AsmLine2.Type::Item);
+        AsmLine2.FindFirst();
+
+        // [GIVEN] Order #2 should have availability warning (needs 6 components, only 2 in inventory minus demand of 2)
+        Assert.IsTrue(AsmLine2."Avail. Warning",
+            'Expected availability warning for Order #2 with insufficient inventory');
+
+        // [WHEN] Re-open Assembly Order #1 and recalculate availability
+        AsmHeader1.Find();
+        AsmLine1.SetRange("Document Type", AsmHeader1."Document Type");
+        AsmLine1.SetRange("Document No.", AsmHeader1."No.");
+        AsmLine1.SetRange(Type, AsmLine1.Type::Item);
+        AsmLine1.FindFirst();
+        AsmLine1.UpdateAvailWarning();
+
+        // [THEN] Order #1 should NOT have availability warning because:
+        // - It has Due Date = Today
+        // - There are 2 components in inventory
+        // - Order #1 only needs 2 components
+        // - Order #2's demand (with later due date) should not affect Order #1's availability
+        Assert.IsFalse(AsmLine1."Avail. Warning",
+            'Expected no availability warning for Order #1. ' +
+            'Future demand from Order #2 should not affect availability for Order #1 with earlier due date.');
+
+        NotificationLifecycleMgt.RecallAllNotifications();
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure AvailWarningShowsWhenInsufficientForDueDate()
+    var
+        ParentItem: Record Item;
+        ChildItem: Record Item;
+        AsmHeader: Record "Assembly Header";
+        AsmLine: Record "Assembly Line";
+        QtyPerComponent: Decimal;
+        OrderQty: Decimal;
+    begin
+        // [SCENARIO] Availability Warning should show when there is insufficient inventory
+        // for the order's due date.
+        Initialize();
+
+        // [GIVEN] An assembled item with one component (Qty Per = 2)
+        QtyPerComponent := 2;
+        CreateAssembledItem(ParentItem, ChildItem, QtyPerComponent);
+
+        // [GIVEN] No inventory for the component
+
+        // [GIVEN] Assembly Order for 1 qty (needs 2 components)
+        OrderQty := 1;
+        CreateAssemblyOrder(AsmHeader, ParentItem."No.", OrderQty, WorkDate());
+        AsmLine.SetRange("Document Type", AsmHeader."Document Type");
+        AsmLine.SetRange("Document No.", AsmHeader."No.");
+        AsmLine.SetRange(Type, AsmLine.Type::Item);
+        AsmLine.FindFirst();
+
+        // [THEN] Should have availability warning (no inventory)
+        Assert.IsTrue(AsmLine."Avail. Warning",
+            'Expected availability warning when there is no inventory for the component');
+
+        NotificationLifecycleMgt.RecallAllNotifications();
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure AvailWarningClearsWhenInventoryAdded()
+    var
+        ParentItem: Record Item;
+        ChildItem: Record Item;
+        AsmHeader: Record "Assembly Header";
+        AsmLine: Record "Assembly Line";
+        QtyPerComponent: Decimal;
+        OrderQty: Decimal;
+    begin
+        // [SCENARIO] Availability Warning should clear when sufficient inventory is added.
+        Initialize();
+
+        // [GIVEN] An assembled item with one component (Qty Per = 2)
+        QtyPerComponent := 2;
+        CreateAssembledItem(ParentItem, ChildItem, QtyPerComponent);
+
+        // [GIVEN] Assembly Order for 1 qty (needs 2 components)
+        OrderQty := 1;
+        CreateAssemblyOrder(AsmHeader, ParentItem."No.", OrderQty, WorkDate());
+        AsmLine.SetRange("Document Type", AsmHeader."Document Type");
+        AsmLine.SetRange("Document No.", AsmHeader."No.");
+        AsmLine.SetRange(Type, AsmLine.Type::Item);
+        AsmLine.FindFirst();
+
+        // [GIVEN] Initially has availability warning (no inventory)
+        Assert.IsTrue(AsmLine."Avail. Warning",
+            'Expected availability warning before adding inventory');
+
+        // [WHEN] Add 2 PCS of component to inventory
+        AddItemToInventory(ChildItem."No.", 2);
+
+        // [WHEN] Recalculate availability
+        AsmLine.Find();
+        AsmLine.UpdateAvailWarning();
+
+        // [THEN] Availability warning should be cleared
+        Assert.IsFalse(AsmLine."Avail. Warning",
+            'Expected no availability warning after adding sufficient inventory');
+
+        NotificationLifecycleMgt.RecallAllNotifications();
+    end;
+
+    local procedure CreateAssembledItem(var ParentItem: Record Item; var ChildItem: Record Item; QtyPer: Decimal)
+    var
+        BOMComponent: Record "BOM Component";
+    begin
+        LibraryInventory.CreateItem(ChildItem);
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::Assembly);
+        ParentItem.Modify(true);
+        LibraryInventory.CreateBOMComponent(
+            BOMComponent, ParentItem."No.", BOMComponent.Type::Item,
+            ChildItem."No.", QtyPer, ChildItem."Base Unit of Measure");
+    end;
+
+    local procedure CreateAssemblyOrder(var AsmHeader: Record "Assembly Header"; ItemNo: Code[20]; Qty: Decimal; DueDate: Date)
+    begin
+        Clear(AsmHeader);
+        AsmHeader."Document Type" := AsmHeader."Document Type"::Order;
+        AsmHeader.Insert(true);
+        AsmHeader.Validate("Due Date", DueDate);
+        AsmHeader.Validate("Item No.", ItemNo);
+        AsmHeader.Validate(Quantity, Qty);
+        AsmHeader.Modify(true);
+        NotificationLifecycleMgt.RecallAllNotifications();
+    end;
+
+    local procedure AddItemToInventory(ItemNo: Code[20]; Quantity: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        ItemJournalTemplate.SetRange(Type, ItemJournalTemplate.Type::Item);
+        ItemJournalTemplate.SetRange(Recurring, false);
+        ItemJournalTemplate.FindFirst();
+        ItemJournalBatch.SetRange("Journal Template Name", ItemJournalTemplate.Name);
+        ItemJournalBatch.FindFirst();
+
+        ItemJournalLine.SetRange("Journal Template Name", ItemJournalTemplate.Name);
+        ItemJournalLine.SetRange("Journal Batch Name", ItemJournalBatch.Name);
+        ItemJournalLine.DeleteAll();
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalTemplate.Name, ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Quantity);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+}

