+    [Test]
+    procedure CreateContractEntryNoFilterWithNonSequentialLines()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobPlanningLine: Record "Job Planning Line";
+        JobPlanningLine2: Record "Job Planning Line";
+        JobPlanningLineFiltered: Record "Job Planning Line";
+        SelectionFilterMgt: Codeunit System.Text.SelectionFilterManagement;
+        RecRef: RecordRef;
+        ContractEntryNoFilter: Text;
+        FirstContractEntryNo: Integer;
+        SecondContractEntryNo: Integer;
+    begin
+        // [SCENARIO] CreateContractEntryNoFilter generates a valid filter when Job Planning Lines are created
+        // with non-sequential Job Contract Entry Nos relative to Line No (e.g., lines inserted "before" existing ones).
+        Initialize();
+
+        // [GIVEN] Create a Job and Job Task.
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] Create first Job Planning Line with a higher Line No (e.g., 20000).
+        JobPlanningLine.Init();
+        JobPlanningLine.Validate("Job No.", JobTask."Job No.");
+        JobPlanningLine.Validate("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine.Validate("Line No.", 20000);
+        JobPlanningLine.Insert(true);
+        FirstContractEntryNo := JobPlanningLine."Job Contract Entry No.";
+
+        // [GIVEN] Create second Job Planning Line with a lower Line No (e.g., 10000) - simulating inserting "before" the first line.
+        // This causes Job Contract Entry No to be higher than the first line, but Line No is lower.
+        JobPlanningLine2.Init();
+        JobPlanningLine2.Validate("Job No.", JobTask."Job No.");
+        JobPlanningLine2.Validate("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine2.Validate("Line No.", 10000);
+        JobPlanningLine2.Insert(true);
+        SecondContractEntryNo := JobPlanningLine2."Job Contract Entry No.";
+
+        // Verify that Job Contract Entry Nos are in ascending order (First < Second)
+        // but Line Nos are in descending order (Second Line No < First Line No)
+        Assert.IsTrue(FirstContractEntryNo < SecondContractEntryNo, 'First Contract Entry No should be less than Second');
+        Assert.IsTrue(JobPlanningLine2."Line No." < JobPlanningLine."Line No.", 'Second Line No should be less than First');
+
+        // [WHEN] Build filter using SetCurrentKey("Job Contract Entry No.") - as the fix does.
+        JobPlanningLineFiltered.SetLoadFields("Job Contract Entry No.");
+        JobPlanningLineFiltered.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLineFiltered.SetRange("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLineFiltered.SetCurrentKey("Job Contract Entry No.");
+        JobPlanningLineFiltered.FindSet();
+        RecRef.GetTable(JobPlanningLineFiltered);
+        ContractEntryNoFilter := SelectionFilterMgt.GetSelectionFilter(RecRef, JobPlanningLineFiltered.FieldNo("Job Contract Entry No."));
+
+        // [THEN] The filter should match both Job Planning Lines when applied.
+        JobPlanningLineFiltered.Reset();
+        JobPlanningLineFiltered.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLineFiltered.SetRange("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLineFiltered.SetFilter("Job Contract Entry No.", ContractEntryNoFilter);
+        Assert.AreEqual(2, JobPlanningLineFiltered.Count(), 'Filter should match both Job Planning Lines');
+
+        // [THEN] Verify both specific Contract Entry Nos are in the filtered set.
+        JobPlanningLineFiltered.SetRange("Job Contract Entry No.", FirstContractEntryNo);
+        Assert.AreEqual(1, JobPlanningLineFiltered.Count(), 'First Contract Entry No should be found');
+        JobPlanningLineFiltered.SetRange("Job Contract Entry No.", SecondContractEntryNo);
+        Assert.AreEqual(1, JobPlanningLineFiltered.Count(), 'Second Contract Entry No should be found');
