+        SalesLineInvoice: Record "Sales Line";
+        Quantity: Decimal;
+        ReducedQuantity: Decimal;
+    begin
+        // [FEATURE] [Item Tracking] [Sales Invoice] [Get Shipment Lines]
+        // [SCENARIO 561982] When reducing quantity on a Sales Invoice line created via Get Shipment Lines, the item tracking lines should be preserved.
+        Initialize();
+
+        // [GIVEN] Item with Lot Tracking and Reserve = Always, FIFO costing
+        Quantity := LibraryRandom.RandIntInRange(5, 10);
+        ReducedQuantity := Quantity - 1;
+        CreateItem(Item, ItemTrackingCodeLotSpecific.Code, Item."Costing Method"::FIFO);
+        Item.Validate(Reserve, Item.Reserve::Always);
+        Item.Modify(true);
+
+        // [GIVEN] Create inventory with lot tracking
+        SetGlobalValue(Item."No.", true, false, false, AssignTracking::LotNo, 0, false);
+        CreateAndPostItemJournalLine(
+          ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", LocationBlue.Code, Quantity * 2, 0, false, AssignTracking::LotNo);
+
+        // [GIVEN] Create Sales Order with Item Tracking and Ship (not Invoice)
+        SetGlobalValue(Item."No.", false, false, false, AssignTracking::None, 0, false);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, CreateCustomer());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", Quantity);
+        SalesLine.Validate("Location Code", LocationBlue.Code);
+        SalesLine.Modify(true);
+        SalesLine.OpenItemTrackingLines(); // Assign Item Tracking on Page Handler
+        LibrarySales.PostSalesDocument(SalesHeader, true, false); // Ship only
+
+        // [GIVEN] Create Sales Invoice and Get Shipment Lines
+        LibrarySales.CreateSalesHeader(SalesHeaderInvoice, SalesHeaderInvoice."Document Type"::Invoice, SalesHeader."Sell-to Customer No.");
+        SalesLineInvoice.Validate("Document Type", SalesHeaderInvoice."Document Type");
+        SalesLineInvoice.Validate("Document No.", SalesHeaderInvoice."No.");
+        LibrarySales.GetShipmentLines(SalesLineInvoice);
+
+        // [GIVEN] Verify tracking lines exist on sales invoice line
+        FindSalesInvoiceLine(SalesLineInvoice, SalesHeaderInvoice."No.", Item."No.");
+        VerifyReservationEntryExists(SalesLineInvoice, true);
+
+        // [WHEN] Reduce the quantity on the Sales Invoice Line
+        SalesLineInvoice.Validate(Quantity, ReducedQuantity);
+        SalesLineInvoice.Modify(true);
+
+        // [THEN] Item tracking lines are preserved on the sales invoice line
+        VerifyReservationEntryExists(SalesLineInvoice, true);
+    end;
+
+    local procedure FindSalesInvoiceLine(var SalesLine: Record "Sales Line"; DocumentNo: Code[20]; ItemNo: Code[20])
+    begin
+        SalesLine.SetRange("Document Type", SalesLine."Document Type"::Invoice);
+        SalesLine.SetRange("Document No.", DocumentNo);
+        SalesLine.SetRange(Type, SalesLine.Type::Item);
+        SalesLine.SetRange("No.", ItemNo);
+        SalesLine.FindFirst();
+    end;
+
+    local procedure VerifyReservationEntryExists(SalesLine: Record "Sales Line"; ExpectExists: Boolean)
+    var
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        ReservationEntry.SetRange("Source Type", Database::"Sales Line");
+        ReservationEntry.SetRange("Source Subtype", SalesLine."Document Type");
+        ReservationEntry.SetRange("Source ID", SalesLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", SalesLine."Line No.");
+        if ExpectExists then
+            Assert.RecordIsNotEmpty(ReservationEntry)
+        else
+            Assert.RecordIsEmpty(ReservationEntry);
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";

