+codeunit 137999 "SCM Trans. Whse Shipment Prev."
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [Transfer Order] [Preview Posting]
+        isInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    [HandlerFunctions('GLPostingPreviewPageHandler')]
+    procedure WhseShipmentLineExistsAfterPreviewPostingTransferOrder()
+    var
+        Item: Record Item;
+        ItemJournalLine: Record "Item Journal Line";
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        LocationInTransit: Record Location;
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        WarehouseShipmentHeader: Record "Warehouse Shipment Header";
+        WarehouseShipmentLine: Record "Warehouse Shipment Line";
+        WarehouseEmployee: Record "Warehouse Employee";
+        WarehouseShipment: TestPage "Warehouse Shipment";
+        WhseShptNo: Code[20];
+        Quantity: Decimal;
+    begin
+        // [SCENARIO] Warehouse shipment line linked to a Transfer Order should still exist after Preview posting
+        // Bug fix - Preview posting should not clear warehouse shipment from the warehouse shipment list page
+
+        Initialize();
+
+        // [GIVEN] Create Location with Require Shipment enabled (simulating SILVER location setup)
+        CreateLocationWithRequireShipment(LocationFrom);
+
+        // [GIVEN] Create destination location
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationTo);
+
+        // [GIVEN] Create In-Transit location
+        LibraryWarehouse.CreateInTransitLocation(LocationInTransit);
+
+        // [GIVEN] Create Warehouse Employee for the location
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, LocationFrom.Code, false);
+
+        // [GIVEN] Create an item
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Post positive adjustment to create inventory in LocationFrom
+        Quantity := LibraryRandom.RandIntInRange(5, 10);
+        CreateAndPostItemJournalLine(
+            ItemJournalLine, ItemJournalLine."Entry Type"::"Positive Adjmt.",
+            Item."No.", Quantity, LocationFrom.Code);
+
+        // [GIVEN] Create Transfer Order from LocationFrom to LocationTo
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, LocationInTransit.Code);
+        LibraryWarehouse.CreateTransferLine(TransferHeader, TransferLine, Item."No.", Quantity);
+        TransferLine.Validate("Qty. to Ship", Quantity);
+        TransferLine.Modify(true);
+
+        // [GIVEN] Release Transfer Order
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [GIVEN] Create Warehouse Shipment from Transfer Order
+        LibraryWarehouse.CreateWhseShipmentFromTO(TransferHeader);
+
+        // [GIVEN] Find and verify the Warehouse Shipment was created
+        WhseShptNo := LibraryWarehouse.FindWhseShipmentNoBySourceDoc(
+            Database::"Transfer Line", 0, TransferHeader."No.");
+        WarehouseShipmentHeader.Get(WhseShptNo);
+
+        // [GIVEN] Verify Warehouse Shipment Line exists before preview
+        WarehouseShipmentLine.SetRange("Source Document", WarehouseShipmentLine."Source Document"::"Outbound Transfer");
+        WarehouseShipmentLine.SetRange("Source No.", TransferHeader."No.");
+        Assert.RecordIsNotEmpty(WarehouseShipmentLine);
+        Commit();
+
+        // [WHEN] Preview Posting action is invoked from the Warehouse Shipment page
+        WarehouseShipment.OpenEdit();
+        WarehouseShipment.GoToRecord(WarehouseShipmentHeader);
+        WarehouseShipment.PreviewPosting.Invoke();
+
+        // [THEN] The Warehouse Shipment Line should still exist after preview posting
+        WarehouseShipmentLine.Reset();
+        WarehouseShipmentLine.SetRange("Source Document", WarehouseShipmentLine."Source Document"::"Outbound Transfer");
+        WarehouseShipmentLine.SetRange("Source No.", TransferHeader."No.");
+        Assert.RecordIsNotEmpty(WarehouseShipmentLine);
+
+        // [THEN] The Warehouse Shipment Header should still exist
+        Assert.IsTrue(WarehouseShipmentHeader.Get(WhseShptNo),
+            'Warehouse Shipment Header should still exist after preview posting');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Trans. Whse Shipment Prev.");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Trans. Whse Shipment Prev.");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        NoSeriesSetup();
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Trans. Whse Shipment Prev.");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        WarehouseSetup: Record "Warehouse Setup";
+    begin
+        LibraryWarehouse.NoSeriesSetup(WarehouseSetup);
+    end;
+
+    local procedure CreateLocationWithRequireShipment(var Location: Record Location)
+    begin
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+        Location.Validate("Require Shipment", true);
+        Location.Modify(true);
+    end;
+
+    local procedure CreateAndPostItemJournalLine(var ItemJournalLine: Record "Item Journal Line"; EntryType: Enum "Item Ledger Entry Type"; ItemNo: Code[20]; Quantity: Decimal; LocationCode: Code[10])
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            EntryType, ItemNo, Quantity);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+    end;
+
+    [PageHandler]
+    [Scope('OnPrem')]
+    procedure GLPostingPreviewPageHandler(var GLPostingPreview: TestPage "G/L Posting Preview")
+    begin
+        // Close the preview page - we just need to verify the shipment line still exists after
+        GLPostingPreview.Close();
+    end;
+}

