diff --git a/App/Layers/W1/Tests/SCM/SCMReservationEntryTracking.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMReservationEntryTracking.Codeunit.al
new file mode 100644
index 00000000..18256a6f
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMReservationEntryTracking.Codeunit.al
@@ -0,0 +1,197 @@
+codeunit 137299 "SCM Reservation Entry Tracking"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Reservation Entry] [Order Tracking] [SCM]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryRandom: Codeunit "Library - Random";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcReservationQuantityIncludesTrackingEntries()
+    var
+        ReservationEntry: array[3] of Record "Reservation Entry";
+        SourceID: Code[20];
+        SourceRefNo: Integer;
+        QtyPerUOM: Decimal;
+        BaseQty1: Decimal;
+        BaseQty2: Decimal;
+        BaseQty3: Decimal;
+        ExpectedQuantity: Decimal;
+    begin
+        // [SCENARIO 525870] CalcReservationQuantity should consider Tracking status entries when calculating Quantity field.
+        // Without fix: Only Reservation status entries are considered, causing rounding errors when Tracking entries exist.
+        // With fix: Both Reservation and Tracking status entries are considered, so Quantity is correctly calculated.
+        Initialize();
+
+        // [GIVEN] Item with UOM conversion of 24 per base (e.g., CASE = 24 PCS)
+        // Create scenario where base qty split into 3 entries each ending in fractional values
+        // that sum to a whole number but would round incorrectly if not all entries considered.
+        QtyPerUOM := 24;
+        SourceID := LibraryUtility.GenerateGUID();
+        SourceRefNo := LibraryRandom.RandInt(10000);
+
+        // Split 288 base qty (12 CASES) into 3 tracking entries:
+        // Entry 1: 13 base (0.54167 in UOM)
+        // Entry 2: 137 base (5.70833 in UOM) - need 137.5 but using 137
+        // Entry 3: 138 base (5.75 in UOM)
+        // Total: 288 base = 12 CASES exactly
+        BaseQty1 := 13;
+        BaseQty2 := 137;
+        BaseQty3 := 138;
+
+        // [GIVEN] First Tracking entry for the source with Quantity (Base) = 13
+        CreateReservationEntryWithTracking(
+            ReservationEntry[1], SourceID, SourceRefNo, BaseQty1, QtyPerUOM);
+
+        // [GIVEN] Second Tracking entry for the same source with Quantity (Base) = 137
+        CreateReservationEntryWithTracking(
+            ReservationEntry[2], SourceID, SourceRefNo, BaseQty2, QtyPerUOM);
+
+        // [WHEN] Third entry is created and Quantity (Base) is validated to 138
+        CreateReservationEntryWithTrackingValidate(
+            ReservationEntry[3], SourceID, SourceRefNo, BaseQty3, QtyPerUOM);
+
+        // [THEN] The calculated Quantity on entry 3 should be correct considering all 3 entries
+        // Total Base = 13 + 137 + 138 = 288
+        // Total Qty in UOM = 288 / 24 = 12 exactly
+        // Entry 1 Qty = Round(13/24) = 0.54167
+        // Entry 2 Qty = Round(137/24) = 5.70833
+        // Entry 3 Qty = 12 - 0.54167 - 5.70833 = 5.75
+        // Sum = 12 exactly
+
+        // Without fix (only Reservation status entries considered):
+        // Entry 3 Qty would be Round(138/24) = 5.75, but first two entries not counted
+        // so Entry 3 Qty = Round((0 + 138)/24) - 0 = 5.75
+        // but entries 1 and 2 have independent quantities, sum may not equal 12
+
+        // Calculate expected quantity for entry 3 (negative for demand)
+        // Total = -288/24 = -12, minus the sum of entries 1 and 2
+        ExpectedQuantity := Round(-(BaseQty1 + BaseQty2 + BaseQty3) / QtyPerUOM, 0.00001) -
+                            ReservationEntry[1].Quantity - ReservationEntry[2].Quantity;
+
+        Assert.AreEqual(
+            ExpectedQuantity,
+            ReservationEntry[3].Quantity,
+            'Quantity on third tracking entry should be calculated considering all tracking entries.');
+
+        // Verify total quantities sum correctly (negative for demand)
+        Assert.AreEqual(
+            -12,
+            ReservationEntry[1].Quantity + ReservationEntry[2].Quantity + ReservationEntry[3].Quantity,
+            'Total Quantity across all tracking entries should equal -12 CASES exactly (negative for demand).');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcReservationQuantitySummedTrackingEntriesNoRoundingError()
+    var
+        ReservationEntry: array[3] of Record "Reservation Entry";
+        SourceID: Code[20];
+        SourceRefNo: Integer;
+        QtyPerUOM: Decimal;
+        BaseQty1: Decimal;
+        BaseQty2: Decimal;
+        BaseQty3: Decimal;
+        TotalQuantity: Decimal;
+    begin
+        // [SCENARIO 525870] When tracking lines are split into 3 entries with fractional values,
+        // the summed Quantity should not have rounding errors like x.00001.
+        Initialize();
+
+        // [GIVEN] Split scenario that caused x.00001 rounding error
+        // Each of 3 entries ends in x.xxxx7 in base, which when divided by QtyPerUOM
+        // and rounded individually would cause small errors to accumulate.
+        QtyPerUOM := 24;
+        SourceID := LibraryUtility.GenerateGUID();
+        SourceRefNo := LibraryRandom.RandInt(10000);
+
+        // Using values that when divided by 24 give repeating decimals
+        // 95/24 = 3.95833..., 97/24 = 4.04166..., 96/24 = 4
+        // Total = 288/24 = 12
+        BaseQty1 := 95;
+        BaseQty2 := 97;
+        BaseQty3 := 96;
+
+        // [GIVEN] Create first two Tracking entries
+        CreateReservationEntryWithTracking(
+            ReservationEntry[1], SourceID, SourceRefNo, BaseQty1, QtyPerUOM);
+        CreateReservationEntryWithTracking(
+            ReservationEntry[2], SourceID, SourceRefNo, BaseQty2, QtyPerUOM);
+
+        // [WHEN] Third entry is created with validation
+        CreateReservationEntryWithTrackingValidate(
+            ReservationEntry[3], SourceID, SourceRefNo, BaseQty3, QtyPerUOM);
+
+        // [THEN] Total Quantity should be exactly -12 (negative for demand), not -12.00001
+        TotalQuantity := ReservationEntry[1].Quantity + ReservationEntry[2].Quantity + ReservationEntry[3].Quantity;
+
+        Assert.AreEqual(
+            -12,
+            TotalQuantity,
+            'Total Quantity should be exactly -12 (negative for demand), without rounding error like -12.00001.');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Reservation Entry Tracking");
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Reservation Entry Tracking");
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Reservation Entry Tracking");
+    end;
+
+    local procedure CreateReservationEntryWithTracking(var ReservationEntry: Record "Reservation Entry"; SourceID: Code[20]; SourceRefNo: Integer; BaseQty: Decimal; QtyPerUOM: Decimal)
+    begin
+        // Create a Tracking status reservation entry without triggering OnValidate for Quantity (Base)
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := 0;
+        ReservationEntry."Source Type" := Database::"Sales Line";
+        ReservationEntry."Source Subtype" := 1; // Order
+        ReservationEntry."Source ID" := SourceID;
+        ReservationEntry."Source Ref. No." := SourceRefNo;
+        ReservationEntry."Source Batch Name" := '';
+        ReservationEntry."Source Prod. Order Line" := 0;
+        ReservationEntry."Reservation Status" := ReservationEntry."Reservation Status"::Tracking;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry."Quantity (Base)" := -BaseQty;
+        ReservationEntry.Quantity := Round(-BaseQty / QtyPerUOM, 0.00001);
+        ReservationEntry.Positive := false;
+        ReservationEntry.Insert(true);
+    end;
+
+    local procedure CreateReservationEntryWithTrackingValidate(var ReservationEntry: Record "Reservation Entry"; SourceID: Code[20]; SourceRefNo: Integer; BaseQty: Decimal; QtyPerUOM: Decimal)
+    begin
+        // Create a Tracking status reservation entry and trigger OnValidate for Quantity (Base)
+        // This calls CalcReservationQuantity which should consider existing Tracking entries
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := 0;
+        ReservationEntry."Source Type" := Database::"Sales Line";
+        ReservationEntry."Source Subtype" := 1; // Order
+        ReservationEntry."Source ID" := SourceID;
+        ReservationEntry."Source Ref. No." := SourceRefNo;
+        ReservationEntry."Source Batch Name" := '';
+        ReservationEntry."Source Prod. Order Line" := 0;
+        ReservationEntry."Reservation Status" := ReservationEntry."Reservation Status"::Tracking;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry.Positive := false;
+        ReservationEntry.Insert(true);
+
+        // Validate Quantity (Base) to trigger CalcReservationQuantity
+        ReservationEntry.Validate("Quantity (Base)", -BaseQty);
+        ReservationEntry.Modify(true);
+    end;
+}

