+    [Test]
+    [Scope('OnPrem')]
+    procedure ManufacturingOverheadConsistentWithMultipleProdOrderLines()
+    var
+        RawItem: Record Item;
+        FGItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder1: Record "Production Order";
+        ProductionOrder2: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        MfgCostCalculationMgt: Codeunit "Mfg. Cost Calculation Mgt.";
+        ShareOfTotalCapCost: Decimal;
+        ExpMatCost: Decimal;
+        ExpCapDirCost: Decimal;
+        ExpSubDirCost: Decimal;
+        ExpCapOvhdCost: Decimal;
+        ExpMfgOvhdCostSingleLine: Decimal;
+        ExpMfgOvhdCostMultiLine: Decimal;
+        IndirectCostPct: Decimal;
+        UnitCost: Decimal;
+        TotalQty: Decimal;
+    begin
+        // [SCENARIO] Manufacturing overhead should be consistent regardless of whether a production order 
+        // has one line with qty 20 or two lines with qty 10 each (same total quantity).
+        // [GIVEN] A raw material item with unit cost and a finished goods item with Indirect Cost %
+        Initialize();
+        UnitCost := 100;
+        IndirectCostPct := 10;
+        TotalQty := 20;
+
+        // Create raw material item with unit cost
+        LibraryInventory.CreateItem(RawItem);
+        RawItem.Validate("Unit Cost", UnitCost);
+        RawItem.Modify(true);
+
+        // Create Production BOM with raw material (Qty per = 1)
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, RawItem."Base Unit of Measure");
+        CreateProductionBOMLine(ProductionBOMHeader, RawItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // Create finished goods item with Indirect Cost %
+        LibraryInventory.CreateItem(FGItem);
+        FGItem.Validate("Replenishment System", FGItem."Replenishment System"::"Prod. Order");
+        FGItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FGItem.Validate("Indirect Cost %", IndirectCostPct);
+        FGItem.Modify(true);
+
+        // [GIVEN] Production Order 1 with a single line, qty = 20
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder1, ProductionOrder1.Status::"Firm Planned",
+            ProductionOrder1."Source Type"::Item, FGItem."No.", TotalQty);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder1, false, true, true, true, false);
+
+        // [GIVEN] Production Order 2 with two lines, qty = 10 each (total = 20)
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder2, ProductionOrder2.Status::"Firm Planned",
+            ProductionOrder2."Source Type"::Item, '', 0);
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder2.Status, ProductionOrder2."No.",
+            FGItem."No.", '', '', TotalQty / 2);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder2, false, false, true, true, false);
+        Clear(ProdOrderLine);
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder2.Status, ProductionOrder2."No.",
+            FGItem."No.", '', '', TotalQty / 2);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder2, false, false, true, true, false);
+
+        // [WHEN] Calculate expected costs for Production Order 1 (single line)
+        ProdOrderLine.Reset();
+        ProdOrderLine.SetRange(Status, ProductionOrder1.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder1."No.");
+        ProdOrderLine.FindFirst();
+        MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+        ExpMfgOvhdCostSingleLine := 0;
+        MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+            ProdOrderLine, ShareOfTotalCapCost, ExpMatCost, ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCostSingleLine);
+
+        // [WHEN] Calculate expected costs for Production Order 2 (two lines)
+        ProdOrderLine.Reset();
+        ProdOrderLine.SetRange(Status, ProductionOrder2.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder2."No.");
+        ExpMfgOvhdCostMultiLine := 0;
+        if ProdOrderLine.FindSet() then
+            repeat
+                MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+                MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+                    ProdOrderLine, ShareOfTotalCapCost, ExpMatCost, ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCostMultiLine);
+            until ProdOrderLine.Next() = 0;
+
+        // [THEN] Manufacturing overhead should be consistent between single line and multiple lines
+        // Expected: Material cost = 100 * 20 = 2000, Mfg Overhead = 10% of 2000 = 200
+        Assert.AreEqual(
+            ExpMfgOvhdCostSingleLine, ExpMfgOvhdCostMultiLine,
+            'Manufacturing overhead should be the same for single line vs. multiple lines with same total quantity');
+    end;
+
+    local procedure CreateProductionBOMLine(ProductionBOMHeader: Record "Production BOM Header"; ItemNo: Code[20]; QuantityPer: Decimal)
+    var
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ItemNo, QuantityPer);
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";

