diff --git a/App/Layers/W1/Tests/ERM/PurchJnlDocAmtDecimalsTest.Codeunit.al b/App/Layers/W1/Tests/ERM/PurchJnlDocAmtDecimalsTest.Codeunit.al
new file mode 100644
index 00000000..86d075fd
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/PurchJnlDocAmtDecimalsTest.Codeunit.al
@@ -0,0 +1,104 @@
+codeunit 139920 "Purch. Jnl. Doc. Amt. Decimals"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase Journal] [Currency] [Decimal Places]
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryJournals: Codeunit "Library - Journals";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        GenJnlManagement: Codeunit GenJnlManagement;
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PurchaseJournalDocumentAmountAcceptsThreeDecimalPlaces()
+    var
+        Vendor: Record Vendor;
+        GenJournalLine: Record "Gen. Journal Line";
+        Currency: Record Currency;
+        PurchaseJournal: TestPage "Purchase Journal";
+        CurrencyCode: Code[10];
+        ExpectedAmount: Decimal;
+    begin
+        // [SCENARIO] Document Amount field in Purchase Journal accepts 3 decimal places when using a currency with 3 decimal places (e.g., TND)
+        // [GIVEN] A currency with 3 decimal places configured (like TND - Tunisian Dinar)
+        Initialize();
+
+        CurrencyCode := CreateCurrencyWithThreeDecimalPlaces();
+        Currency.Get(CurrencyCode);
+
+        // [GIVEN] A vendor exists
+        LibraryPurchase.CreateVendor(Vendor);
+
+        // [WHEN] User opens Purchase Journal and enters an amount with 3 decimal places (1.234)
+        ExpectedAmount := 1.234;
+        PurchaseJournal.OpenEdit();
+        PurchaseJournal.New();
+        PurchaseJournal."Document Type".SetValue(GenJournalLine."Document Type"::Invoice);
+        PurchaseJournal."Account Type".SetValue(GenJournalLine."Account Type"::Vendor);
+        PurchaseJournal."Account No.".SetValue(Vendor."No.");
+        PurchaseJournal."Currency Code".SetValue(CurrencyCode);
+
+        // [THEN] The Document Amount field accepts the 3 decimal value without error
+        PurchaseJournal.DocumentAmount.SetValue(ExpectedAmount);
+
+        // [THEN] The value is correctly stored with 3 decimal places
+        Assert.AreEqual(
+            Format(ExpectedAmount),
+            PurchaseJournal.DocumentAmount.Value,
+            'Document Amount should accept 3 decimal places for currencies configured with 3 decimal places');
+
+        // [THEN] The Amount field has the correct negated value (for Invoice document type)
+        Assert.AreEqual(
+            Format(-ExpectedAmount),
+            PurchaseJournal.Amount.Value,
+            'Amount should be the negative of Document Amount for Invoice document type');
+
+        PurchaseJournal.Close();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Purch. Jnl. Doc. Amt. Decimals");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Purch. Jnl. Doc. Amt. Decimals");
+
+        GenJnlManagement.SetJournalSimplePageModePreference(true, Page::"Purchase Journal");
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateAccountInVendorPostingGroups();
+        LibraryERMCountryData.RemoveBlankGenJournalTemplate();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Purch. Jnl. Doc. Amt. Decimals");
+    end;
+
+    local procedure CreateCurrencyWithThreeDecimalPlaces(): Code[10]
+    var
+        Currency: Record Currency;
+        CurrencyCode: Code[10];
+    begin
+        // Create a currency with 3 decimal places to simulate TND (Tunisian Dinar)
+        CurrencyCode := LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), 1, 1);
+        Currency.Get(CurrencyCode);
+        Currency.Validate("Amount Decimal Places", '3:3');
+        Currency.Validate("Amount Rounding Precision", 0.001);
+        Currency.Modify(true);
+        exit(CurrencyCode);
+    end;
+}

