+codeunit 139614 "Shpfy Copy Document Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Any: Codeunit Any;
+        LibraryAssert: Codeunit "Library Assert";
+        LibrarySales: Codeunit "Library - Sales";
+
+    [Test]
+    procedure CopyDocumentClearsShopifyFieldsFromPostedInvoice()
+    var
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        SalesHeader: Record "Sales Header";
+        Customer: Record Customer;
+        CopyDocumentMgt: Codeunit "Copy Document Mgt.";
+        ShopifyOrderId: BigInteger;
+        ShopifyRefundId: BigInteger;
+        ShopifyOrderNo: Code[50];
+    begin
+        // [SCENARIO] When copying a posted sales invoice that was exported to Shopify,
+        // the Shopify Order Id, Shopify Order No., and Shopify Refund Id should be cleared
+        // so the new invoice can be exported independently.
+
+        // [GIVEN] A posted sales invoice with Shopify Order Id, Order No., and Refund Id populated
+        LibrarySales.CreateCustomer(Customer);
+        ShopifyOrderId := Any.IntegerInRange(10000, 99999);
+        ShopifyOrderNo := CopyStr(Any.AlphanumericText(20), 1, MaxStrLen(ShopifyOrderNo));
+        ShopifyRefundId := Any.IntegerInRange(10000, 99999);
+        CreatePostedSalesInvoiceWithShopifyFields(SalesInvoiceHeader, Customer."No.", ShopifyOrderId, ShopifyOrderNo, ShopifyRefundId);
+
+        // [GIVEN] A new sales invoice header to copy to
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+
+        // [WHEN] Copy Document is executed to copy the posted invoice
+        CopyDocumentMgt.SetProperties(true, false, false, false, false, false, false);
+        CopyDocumentMgt.CopySalesDoc("Sales Document Type From"::"Posted Invoice", SalesInvoiceHeader."No.", SalesHeader);
+
+        // [THEN] The Shopify Order Id should be cleared (0)
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Order Id", 'Shpfy Order Id should be cleared after copy');
+
+        // [THEN] The Shopify Order No. should be cleared (blank)
+        LibraryAssert.AreEqual('', SalesHeader."Shpfy Order No.", 'Shpfy Order No. should be cleared after copy');
+
+        // [THEN] The Shopify Refund Id should be cleared (0)
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Refund Id", 'Shpfy Refund Id should be cleared after copy');
+    end;
+
+    local procedure CreatePostedSalesInvoiceWithShopifyFields(var SalesInvoiceHeader: Record "Sales Invoice Header"; CustomerNo: Code[20]; ShopifyOrderId: BigInteger; ShopifyOrderNo: Code[50]; ShopifyRefundId: BigInteger)
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        Item: Record Item;
+        LibraryInventory: Codeunit "Library - Inventory";
+        PostedInvoiceNo: Code[20];
+    begin
+        // Create and post a sales invoice
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, CustomerNo);
+        LibraryInventory.CreateItem(Item);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", 1);
+        SalesLine.Validate("Unit Price", 100);
+        SalesLine.Modify(true);
+
+        PostedInvoiceNo := LibrarySales.PostSalesDocument(SalesHeader, false, true);
+
+        // Find the posted invoice and update with Shopify fields
+        SalesInvoiceHeader.Get(PostedInvoiceNo);
+        SalesInvoiceHeader."Shpfy Order Id" := ShopifyOrderId;
+        SalesInvoiceHeader."Shpfy Order No." := ShopifyOrderNo;
+        SalesInvoiceHeader.Modify();
+    end;
+}

