@@ -0,0 +1,154 @@
+codeunit 135399 "Item Charge Blank Qty To Ship"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Item Charge] [Sales Return Order] [Default Quantity to Ship]
+    end;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('PostedSalesDocumentLinesHandler,ItemChargeAssignmentSalesHandler,StrMenuHandler')]
+    [Scope('OnPrem')]
+    procedure ItemChargeToSalesReturnOrderWhenDefaultQtyToShipIsBlank()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesLineItem: Record "Sales Line";
+        SalesLineCharge: Record "Sales Line";
+        SalesHeaderReturnOrder: Record "Sales Header";
+        SalesLineReturnOrder: Record "Sales Line";
+        Item: Record Item;
+        ItemChargeNo: Code[20];
+        ItemQty: Decimal;
+        ChargeQty: Decimal;
+    begin
+        // [SCENARIO] Item Charge should be successfully pulled into Sales Return Order when Default Quantity to Ship is set to Blank
+        // [GIVEN] Sales & Receivables Setup with Default Quantity to Ship = Blank
+        Initialize();
+        SetDefaultQtyToShipToBlank();
+
+        // [GIVEN] Create Sales Order with Item line and Item Charge line
+        ItemQty := LibraryRandom.RandIntInRange(5, 25);
+        ChargeQty := LibraryRandom.RandIntInRange(5, 25);
+        LibraryInventory.CreateItem(Item);
+        ItemChargeNo := LibraryInventory.CreateItemChargeNo();
+
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLineItem, SalesHeader, SalesLineItem.Type::Item, Item."No.", ItemQty);
+        SalesLineItem.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLineItem.Modify(true);
+
+        LibrarySales.CreateSalesLine(SalesLineCharge, SalesHeader, SalesLineCharge.Type::"Charge (Item)", ItemChargeNo, ChargeQty);
+        SalesLineCharge.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLineCharge.Modify(true);
+
+        // [GIVEN] Item Charge Assignment is done
+        LibraryVariableStorage.Enqueue(ChargeQty);
+        SalesLineCharge.ShowItemChargeAssgnt();
+
+        // [GIVEN] Set Qty. to Ship on Sales Lines since Default Qty to Ship is Blank
+        SalesLineItem.Validate("Qty. to Ship", ItemQty);
+        SalesLineItem.Modify(true);
+        SalesLineCharge.Validate("Qty. to Ship", ChargeQty);
+        SalesLineCharge.Modify(true);
+
+        // [GIVEN] Post (Ship and Invoice) the Sales Order
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+
+        // [GIVEN] Create Sales Return Order for same customer
+        LibrarySales.CreateSalesHeader(
+            SalesHeaderReturnOrder, SalesHeaderReturnOrder."Document Type"::"Return Order", SalesHeader."Sell-to Customer No.");
+
+        // [WHEN] Get Posted Document Lines to Reverse (marking both Item and Charge Item lines)
+        LibraryVariableStorage.Enqueue(3); // 3 = Posted Invoices option
+        SalesHeaderReturnOrder.GetPstdDocLinesToReverse();
+
+        // [THEN] Both Item and Item Charge lines should be copied to Sales Return Order without error
+        SalesLineReturnOrder.SetRange("Document Type", SalesHeaderReturnOrder."Document Type");
+        SalesLineReturnOrder.SetRange("Document No.", SalesHeaderReturnOrder."No.");
+        SalesLineReturnOrder.SetRange(Type, SalesLineReturnOrder.Type::Item);
+        SalesLineReturnOrder.SetRange("No.", Item."No.");
+        Assert.RecordIsNotEmpty(SalesLineReturnOrder);
+
+        SalesLineReturnOrder.SetRange(Type, SalesLineReturnOrder.Type::"Charge (Item)");
+        SalesLineReturnOrder.SetRange("No.", ItemChargeNo);
+        Assert.RecordIsNotEmpty(SalesLineReturnOrder);
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Item Charge Blank Qty To Ship");
+        LibrarySetupStorage.Restore();
+        LibraryVariableStorage.Clear();
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Item Charge Blank Qty To Ship");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+
+        LibrarySetupStorage.Save(Database::"Sales & Receivables Setup");
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Item Charge Blank Qty To Ship");
+    end;
+
+    local procedure SetDefaultQtyToShipToBlank()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Default Quantity to Ship", SalesReceivablesSetup."Default Quantity to Ship"::Blank);
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PostedSalesDocumentLinesHandler(var PostedSalesDocumentLines: TestPage "Posted Sales Document Lines")
+    begin
+        PostedSalesDocumentLines.PostedInvoices.First();
+        PostedSalesDocumentLines.OK().Invoke();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ItemChargeAssignmentSalesHandler(var ItemChargeAssignmentSales: TestPage "Item Charge Assignment (Sales)")
+    var
+        QtyToAssign: Decimal;
+    begin
+        QtyToAssign := LibraryVariableStorage.DequeueDecimal();
+        ItemChargeAssignmentSales."Qty. to Assign".SetValue(QtyToAssign);
+        ItemChargeAssignmentSales.OK().Invoke();
+    end;
+
+    [StrMenuHandler]
+    [Scope('OnPrem')]
+    procedure StrMenuHandler(Options: Text[1024]; var Choice: Integer; Instructions: Text[1024])
+    begin
+        // Select Posted Invoices option (option 3)
+        Choice := LibraryVariableStorage.DequeueInteger();
+    end;
+}

