@@ -6853,4 +6853,80 @@ ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name
     begin
         LibraryReportDataset.RunReportAndLoad(Report::"Standard Purchase - Order", PurchaseHeader, '');
     end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CarryOutActionMsgRespectsActionMessageFilter()
+    var
+        Item: Record Item;
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        ReqWkshTemplate: Record "Req. Wksh. Template";
+        CarryOutActionMsgPlan: Report "Carry Out Action Msg. - Plan.";
+        CancelLineCount: Integer;
+        NewLineCount: Integer;
+    begin
+        // [SCENARIO] When a filter is set on Action Message in the Planning Worksheet and Carry Out Action Message is run,
+        // only the filtered lines should be processed, not all lines.
+        // [GIVEN] An item with Reordering Policy = Order
+        Initialize();
+        CreateItem(Item, Item."Reordering Policy"::Order, Item."Replenishment System"::Purchase);
+
+        // [GIVEN] A Purchase Order for the item with Expected Receipt Date in the past (will create Cancel action)
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, Item."Vendor No.");
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", LibraryRandom.RandInt(10));
+        PurchaseLine.Validate("Expected Receipt Date", WorkDate() - 10);
+        PurchaseLine.Modify(true);
+
+        // [GIVEN] A Sales Order for the same item with Shipment Date in the future (will create New action)
+        CreateSalesOrder(SalesHeader, SalesLine, Item."No.", LibraryRandom.RandInt(10));
+        UpdateShipmentDateOnSalesLine(SalesLine, WorkDate() + 30);
+
+        // [GIVEN] Calculate Regenerative Plan to generate planning lines
+        SelectRequisitionTemplate(ReqWkshTemplate, ReqWkshTemplate.Type::Planning);
+        LibraryPlanning.CreateRequisitionWkshName(RequisitionWkshName, ReqWkshTemplate.Name);
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item, WorkDate(), WorkDate() + 60);
+
+        // [GIVEN] Accept Action Message only for lines with Action Message = Cancel
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        RequisitionLine.FindSet();
+        CancelLineCount := RequisitionLine.Count;
+        repeat
+            RequisitionLine.Validate("Accept Action Message", true);
+            RequisitionLine.Modify(true);
+        until RequisitionLine.Next() = 0;
+
+        // Count New lines before carry out
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        NewLineCount := RequisitionLine.Count;
+        Assert.IsTrue(NewLineCount > 0, 'Expected at least one New action line');
+
+        // [WHEN] Carry Out Action Message with filter on Action Message = Cancel
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        RequisitionLine.FindFirst();
+        Commit();
+        CarryOutActionMsgPlan.SetReqWkshLine(RequisitionLine);
+        CarryOutActionMsgPlan.InitializeRequest(0, 1, 0, 0); // Make Purchase Orders only
+        CarryOutActionMsgPlan.SetTableView(RequisitionLine);
+        CarryOutActionMsgPlan.UseRequestPage(false);
+        CarryOutActionMsgPlan.RunModal();
+
+        // [THEN] Only the Cancel line should be processed
+        // [THEN] The New line should still exist in the requisition worksheet
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        Assert.AreEqual(NewLineCount, RequisitionLine.Count, 'New action lines should remain after Carry Out when filtered by Cancel');
+
+        // [THEN] The Cancel lines should have been processed (no longer exist or purchase order cancelled)
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        Assert.AreEqual(0, RequisitionLine.Count, 'Cancel action lines should have been processed');
+    end;
 }

