+    [Test]
+    procedure PurchInvoicePricesInclVATWith100PctNonDeductibleVAT()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        PurchHeader: Record "Purchase Header";
+        PurchLine: Record "Purchase Line";
+        GLAccount: Record "G/L Account";
+        Vendor: Record Vendor;
+        VATEntry: Record "VAT Entry";
+        DocNo: Code[20];
+        DirectUnitCostInclVAT: Decimal;
+        ExpectedNonDedVATBase: Decimal;
+        ExpectedNonDedVATAmount: Decimal;
+    begin
+        // [FEATURE] [Non-Deductible VAT] [Prices Including VAT]
+        // [SCENARIO] Posting purchase invoice with Prices Including VAT and 100% Non-Deductible VAT should not cause rounding errors
+
+        Initialize();
+        // [GIVEN] Normal VAT Posting Setup with "VAT %" = 20 and "Non-Deductible VAT %" = 100
+        LibraryNonDeductibleVAT.CreateNonDeductibleNormalVATPostingSetup(VATPostingSetup);
+        VATPostingSetup.Validate("Non-Deductible VAT %", 100);
+        VATPostingSetup.Modify(true);
+
+        // [GIVEN] Vendor with "Prices Including VAT" = TRUE
+        Vendor.Get(LibraryPurchase.CreateVendorWithVATBusPostingGroup(VATPostingSetup."VAT Bus. Posting Group"));
+        Vendor.Validate("Prices Including VAT", true);
+        Vendor.Modify(true);
+
+        // [GIVEN] G/L Account with VAT Prod. Posting Group
+        LibraryERM.CreateGLAccount(GLAccount);
+        GLAccount.Validate("Gen. Posting Type", GLAccount."Gen. Posting Type"::Purchase);
+        GLAccount.Validate("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        GLAccount.Validate("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        GLAccount.Modify(true);
+
+        // [GIVEN] Purchase invoice with "Prices Including VAT" and a specific amount that would cause rounding issues
+        LibraryPurchase.CreatePurchHeader(PurchHeader, PurchHeader."Document Type"::Invoice, Vendor."No.");
+        DirectUnitCostInclVAT := 14.19; // This amount causes rounding issues when calculating base from prices including VAT
+        LibraryPurchase.CreatePurchaseLine(PurchLine, PurchHeader, PurchLine.Type::"G/L Account", GLAccount."No.", 1);
+        PurchLine.Validate("Direct Unit Cost", DirectUnitCostInclVAT);
+        PurchLine.Modify(true);
+
+        // Calculate expected values: With 100% Non-Deductible VAT, VAT Entry Base and Amount should be 0
+        ExpectedNonDedVATBase := PurchLine."VAT Base Amount";
+        ExpectedNonDedVATAmount := PurchLine."Amount Including VAT" - PurchLine.Amount;
+
+        // [WHEN] Post purchase document
+        DocNo := LibraryPurchase.PostPurchaseDocument(PurchHeader, true, true);
+
+        // [THEN] VAT Entry has Base = 0 and Amount = 0 (all VAT is non-deductible)
+        FindVATEntry(VATEntry, DocNo);
+        LibraryNonDeductibleVAT.VerifyVATAmountsInVATEntry(VATEntry, 0, 0, ExpectedNonDedVATBase, ExpectedNonDedVATAmount);
+    end;
