+        GenJournalLine.Modify();
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [GIVEN] Post another payment using the alternative Customer Posting Group
+        Amount[2] := -LibraryRandom.RandDecInRange(300, 400, 2);
