+        // [SCENARIO] When issuing Finance Charge Memo with alternative Customer Posting Group, G/L Entries should be posted to the Receivables Account of the alternative posting group
+
+        Initialize();
+
+        // [GIVEN] Sales & Receivables Setup has Allow Multiple Posting Groups enabled
