+        FinanceChargeTerms.Validate("Additional Fee (LCY)", LibraryRandom.RandDecInRange(10, 100, 2));
+        FinanceChargeTerms.Modify(true);
+        Customer.Validate("Fin. Charge Terms Code", FinanceChargeTerms.Code);
+        Customer.Validate("Allow Multiple Posting Groups", true);
+        Customer.Modify(true);
+
+        // [GIVEN] Original Customer Posting Group
+        CustomerPostingGroup.Get(Customer."Customer Posting Group");
+
+        // [GIVEN] Alternative Customer Posting Group with different Receivables Account
+        LibrarySales.CreateCustomerPostingGroup(CustomerPostingGroup2);
+        LibrarySales.CreateAltCustomerPostingGroup(Customer."Customer Posting Group", CustomerPostingGroup2.Code);
+
+        // [GIVEN] Finance Charge Memo created for the Customer with alternative Customer Posting Group
+        LibraryERM.CreateFinanceChargeMemoHeader(FinanceChargeMemoHeader, Customer."No.");
+        FinanceChargeMemoHeader.Validate("Customer Posting Group", CustomerPostingGroup2.Code);
+        FinanceChargeMemoHeader.Modify(true);
