+            CustomerPostingGroup2.Code, IssuedFinChargeMemoHeader."Customer Posting Group",
+            'Customer Posting Group in Issued Finance Charge Memo Header is not correct.');
+
+        // [THEN] Customer Ledger Entry has the alternative Customer Posting Group
+        CustLedgerEntry.SetRange("Customer No.", Customer."No.");
+        CustLedgerEntry.SetRange("Document Type", CustLedgerEntry."Document Type"::"Finance Charge Memo");
+        CustLedgerEntry.FindFirst();
+        Assert.AreEqual(
+            CustomerPostingGroup2.Code, CustLedgerEntry."Customer Posting Group",
+            'Customer Posting Group in Customer Ledger Entry is not correct.');
+
+        // [THEN] G/L Entry exists for the Receivables Account of the alternative Customer Posting Group
+        GLEntry.SetRange("Document No.", IssuedFinChargeMemoHeader."No.");
+        GLEntry.SetRange("G/L Account No.", CustomerPostingGroup2."Receivables Account");
