+        // [THEN] No G/L Entry exists for the Receivables Account of the original Customer Posting Group
+        GLEntry.SetRange("G/L Account No.", CustomerPostingGroup."Receivables Account");
+        Assert.RecordIsEmpty(GLEntry);
+    end;
