+        // [WHEN] Executing the codeunit "Shpfy Create Item" with the "Shpfy Variant" Record.
+        Codeunit.Run(Codeunit::"Shpfy Create Item", ShopifyVariant);
+
+        // [THEN] On the "Shpfy Variant" record, the field "Item SystemId" must be filled in and the Item record must exist.
+        LibraryAssert.IsFalse(IsNullGuid(ShopifyVariant."Item SystemId"), 'Item SystemId <> NullGuid');
+        LibraryAssert.IsTrue(Item.GetBySystemId(ShopifyVariant."Item SystemId"), 'Get Item');
+
+        // [THEN] The Item's Unit Price and Unit Cost should be converted from foreign currency to LCY
+        // Price in DKK * Exchange Rate Factor = Price in LCY
+        ExpectedUnitPrice := Round(CurrencyExchangeRate.ExchangeAmtFCYToLCY(WorkDate(), Currency.Code, ShopifyVariant.Price, CurrencyExchangeRate.ExchangeRate(WorkDate(), Currency.Code)));
+        ExpectedUnitCost := Round(CurrencyExchangeRate.ExchangeAmtFCYToLCY(WorkDate(), Currency.Code, ShopifyVariant."Unit Cost", CurrencyExchangeRate.ExchangeRate(WorkDate(), Currency.Code)));
+
+        // Verify that the price is NOT equal to the original (unconverted) price - this is the bug we're testing for
+        LibraryAssert.AreNotEqual(ShopifyVariant.Price, Item."Unit Price", 'Unit Price should be converted from foreign currency');
+        LibraryAssert.AreNotEqual(ShopifyVariant."Unit Cost", Item."Unit Cost", 'Unit Cost should be converted from foreign currency');
+
+        // Verify that the price IS equal to the expected converted price
+        LibraryAssert.AreEqual(ExpectedUnitPrice, Item."Unit Price", 'Unit Price should match converted amount');
+        LibraryAssert.AreEqual(ExpectedUnitCost, Item."Unit Cost", 'Unit Cost should match converted amount');
+    end;
 }

