+        // [GIVEN] Set the Item UOM 'Qty. Rounding Precision' = 1 for the component's base UOM
+        ItemUnitOfMeasure.Get(CompItem."No.", CompItem."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] A finished goods item with Replenishment System = Prod. Order, Rounding Precision = 1
+        LibraryInventory.CreateItem(ProdItem);
+        ProdItem.Validate("Replenishment System", ProdItem."Replenishment System"::"Prod. Order");
+        ProdItem.Validate("Rounding Precision", 1);
