+codeunit 137789 "SCM Invt. Pick FEFO Rounding"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [Inventory Pick] [FEFO] [Rounding]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibrarySales: Codeunit "Library - Sales";
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('MessageHandler')]
+    [Scope('OnPrem')]
+    procedure InvtPickQuantityRoundingWithFEFOMultipleBinsLots()
+    var
+        Location: Record Location;
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ItemTrackingCode: Record "Item Tracking Code";
+        Bin: array[3] of Record Bin;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        LotNo: array[6] of Code[50];
+        ExpirationDate: array[6] of Date;
+        QtyPerUOM: Decimal;
+        SalesQty: Decimal;
+        TotalPickedQty: Decimal;
+        i: Integer;
+    begin
+        // [FEATURE] [FEFO] [Item Tracking] [Inventory Pick] [Rounding]
+        // [SCENARIO] When creating an inventory pick with FEFO and multiple lots/bins with a non-standard UOM,
+        // the sum of picked quantities should equal the requested quantity without rounding errors.
+        Initialize();
+
+        // [GIVEN] Location with Bins, Require Pick and Pick According to FEFO
+        CreateFEFOLocationWithBins(Location, Bin);
+
+        // [GIVEN] Item with Lot tracking, expiration dates, and non-standard UOM (like PACK with Qty per UOM = 2.888)
+        QtyPerUOM := 2.888;
+        CreateItemWithLotTrackingAndUOM(Item, ItemTrackingCode, ItemUnitOfMeasure, QtyPerUOM);
+
+        // [GIVEN] Create lot numbers with different expiration dates (earlier dates = higher priority in FEFO)
+        for i := 1 to 6 do begin
+            LotNo[i] := StrSubstNo('LOT%1', Format(i, 2, '<Integer,2><Filler Character,0>'));
+        end;
+
+        // Different expiration dates to ensure FEFO ordering
+        ExpirationDate[1] := CalcDate('<-1M>', WorkDate()); // LOT01 - later expiration (Nov 30)
+        ExpirationDate[2] := CalcDate('<-2M>', WorkDate()); // LOT02 - earlier expiration (May 16)
+        ExpirationDate[3] := CalcDate('<-1M-5D>', WorkDate()); // LOT03 - Sep 25
+        ExpirationDate[4] := CalcDate('<-3M>', WorkDate()); // LOT04 - earliest (Jun 6)
+        ExpirationDate[5] := CalcDate('<-2M+10D>', WorkDate()); // LOT05 - Jul 13
+        ExpirationDate[6] := CalcDate('<-1M-5D>', WorkDate()); // LOT06 - Sep 25
+
+        // [GIVEN] Post inventory across multiple bins with quantities that will cause rounding issues
+        // Bin 1 (S-03-0001)
+        PostItemJournalLineWithLotAndExpDate(Item."No.", Location.Code, Bin[1].Code, LotNo[1], 434.97616, ExpirationDate[1]);
+        PostItemJournalLineWithLotAndExpDate(Item."No.", Location.Code, Bin[1].Code, LotNo[3], 17.3126, ExpirationDate[3]);
+        PostItemJournalLineWithLotAndExpDate(Item."No.", Location.Code, Bin[1].Code, LotNo[6], 17.0373, ExpirationDate[6]);
+
+        // Bin 2 (S-03-0002)
+        PostItemJournalLineWithLotAndExpDate(Item."No.", Location.Code, Bin[2].Code, LotNo[1], 4.13394, ExpirationDate[1]);
+        PostItemJournalLineWithLotAndExpDate(Item."No.", Location.Code, Bin[2].Code, LotNo[2], 4.34355, ExpirationDate[1]); // LOT02 with later date in bin2
+        PostItemJournalLineWithLotAndExpDate(Item."No.", Location.Code, Bin[2].Code, LotNo[3], 151.33333, ExpirationDate[3]);
+        PostItemJournalLineWithLotAndExpDate(Item."No.", Location.Code, Bin[2].Code, LotNo[4], 40.01221, ExpirationDate[4]);
+
+        // Bin 3 (S-03-0003)
+        PostItemJournalLineWithLotAndExpDate(Item."No.", Location.Code, Bin[3].Code, LotNo[2], 1.78787, ExpirationDate[2]); // LOT02 with earlier date in bin3
+        PostItemJournalLineWithLotAndExpDate(Item."No.", Location.Code, Bin[3].Code, LotNo[3], 42.73313, ExpirationDate[3]);
+        PostItemJournalLineWithLotAndExpDate(Item."No.", Location.Code, Bin[3].Code, LotNo[5], 4.013, ExpirationDate[5]);
+
+        // [GIVEN] Sales Order for 248 PACK (which is 248 * 2.888 = 716.224 PCS in base UOM)
+        SalesQty := 248;
+        CreateSalesOrderWithUOM(SalesHeader, SalesLine, Item."No.", Location.Code, SalesQty, ItemUnitOfMeasure.Code);
+
+        // [WHEN] Create Inventory Pick
+        LibrarySales.ReleaseSalesDocument(SalesHeader);
+        LibraryWarehouse.CreateInvtPutPickMovement(
+            WarehouseActivityLine."Source Document"::"Sales Order", SalesHeader."No.", false, true, false);
+
+        // [THEN] Sum of Quantity on pick lines should equal the sales quantity (248 PACK)
+        WarehouseActivityLine.SetRange("Source Type", Database::"Sales Line");
+        WarehouseActivityLine.SetRange("Source Subtype", SalesLine."Document Type");
+        WarehouseActivityLine.SetRange("Source No.", SalesHeader."No.");
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Invt. Pick");
+
+        TotalPickedQty := 0;
+        if WarehouseActivityLine.FindSet() then
+            repeat
+                TotalPickedQty += WarehouseActivityLine.Quantity;
+            until WarehouseActivityLine.Next() = 0;
+
+        // Verify that the total picked quantity equals the requested sales quantity
+        Assert.AreEqual(
+            SalesQty,
+            TotalPickedQty,
+            'Total picked quantity should equal the sales quantity without rounding errors');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Invt. Pick FEFO Rounding");
+        WarehouseEmployee.DeleteAll();
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Invt. Pick FEFO Rounding");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateLocalData();
+        LibraryERMCountryData.UpdateJournalTemplMandatory(false);
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Invt. Pick FEFO Rounding");
+    end;
+
+    local procedure CreateFEFOLocationWithBins(var Location: Record Location; var Bin: array[3] of Record Bin)
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+        i: Integer;
+    begin
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, true, false, false);
+        Location.Validate("Pick According to FEFO", true);
+        Location.Modify(true);
+
+        for i := 1 to 3 do
+            LibraryWarehouse.CreateBin(
+                Bin[i], Location.Code,
+                CopyStr(
+                    LibraryUtility.GenerateRandomCode(Bin[i].FieldNo(Code), Database::Bin), 1,
+                    LibraryUtility.GetFieldLength(Database::Bin, Bin[i].FieldNo(Code))), '', '');
+
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+    end;
+
+    local procedure CreateItemWithLotTrackingAndUOM(var Item: Record Item; var ItemTrackingCode: Record "Item Tracking Code"; var ItemUnitOfMeasure: Record "Item Unit of Measure"; QtyPerUOM: Decimal)
+    begin
+        LibraryItemTracking.CreateItemTrackingCodeWithExpirationDate(ItemTrackingCode, false, true);
+        ItemTrackingCode.Validate("Lot Warehouse Tracking", true);
+        ItemTrackingCode.Modify(true);
+
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        Item.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        Item.Modify(true);
+
+        // Create additional UOM with specific Qty per UOM that causes rounding issues
+        LibraryInventory.CreateItemUnitOfMeasureCode(ItemUnitOfMeasure, Item."No.", QtyPerUOM);
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 0.00001);
+        ItemUnitOfMeasure.Modify(true);
+
+        Item.Validate("Sales Unit of Measure", ItemUnitOfMeasure.Code);
+        Item.Modify(true);
+    end;
+
+    local procedure PostItemJournalLineWithLotAndExpDate(ItemNo: Code[20]; LocationCode: Code[10]; BinCode: Code[20]; LotNo: Code[50]; Qty: Decimal; ExpirationDate: Date)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, ItemNo, LocationCode, BinCode, Qty);
+        LibraryItemTracking.CreateItemJournalLineItemTracking(ReservationEntry, ItemJournalLine, '', LotNo, Qty);
+        ReservationEntry.Validate("Expiration Date", ExpirationDate);
+        ReservationEntry.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    local procedure CreateSalesOrderWithUOM(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; ItemNo: Code[20]; LocationCode: Code[10]; Qty: Decimal; UOMCode: Code[10])
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, ItemNo, Qty);
+        SalesLine.Validate("Location Code", LocationCode);
+        SalesLine.Validate("Unit of Measure Code", UOMCode);
+        SalesLine.Modify(true);
+    end;
+
+    [MessageHandler]
+    [Scope('OnPrem')]
+    procedure MessageHandler(Message: Text[1024])
+    begin
+        // Message Handler for inventory pick creation messages
+    end;
+}

