+    [Test]
+    [Scope('OnPrem')]
+    procedure PlanningWorksheetNoSuggestionWhenItemConsumedInMultipleSubassemblies()
+    var
+        Item1: Record Item;
+        Item2A: Record Item;
+        Item2B: Record Item;
+        Item3: Record Item;
+        ProductionBOMHeader1: Record "Production BOM Header";
+        ProductionBOMHeader2: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        RequisitionLine: Record "Requisition Line";
+    begin
+        // [SCENARIO] When Item3 is consumed in multiple subassemblies (Item2A and Item2B) that are part of Item1,
+        // planning worksheet should not suggest any changes if demand and supply are already balanced.
+        Initialize();
+
+        // [GIVEN] Create four items with Replenishment = Prod. Order, Manufacturing Policy = Make-to-Order, Reordering Policy = Lot-for-Lot
+        CreateMakeToOrderProdItem(Item1);
+        CreateMakeToOrderProdItem(Item2A);
+        CreateMakeToOrderProdItem(Item2B);
+        CreateMakeToOrderProdItem(Item3);
+
+        // [GIVEN] Create Production BOM for Item2A with Item3 as component (Qty per = 1)
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader2, Item3."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader2, ProductionBOMLine, '', ProductionBOMLine.Type::Item, Item3."No.", 1);
+        ProductionBOMHeader2.Validate(Status, ProductionBOMHeader2.Status::Certified);
+        ProductionBOMHeader2.Modify(true);
+
+        // [GIVEN] Assign Production BOM to Item2A and Item2B (both use Item3)
+        Item2A.Validate("Production BOM No.", ProductionBOMHeader2."No.");
+        Item2A.Modify(true);
+        Item2B.Validate("Production BOM No.", ProductionBOMHeader2."No.");
+        Item2B.Modify(true);
+
+        // [GIVEN] Create Production BOM for Item1 with Item2A and Item2B as components (Qty per = 1 each)
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader1, Item2A."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader1, ProductionBOMLine, '', ProductionBOMLine.Type::Item, Item2A."No.", 1);
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader1, ProductionBOMLine, '', ProductionBOMLine.Type::Item, Item2B."No.", 1);
+        ProductionBOMHeader1.Validate(Status, ProductionBOMHeader1.Status::Certified);
+        ProductionBOMHeader1.Modify(true);
+
+        // [GIVEN] Assign Production BOM to Item1
+        Item1.Validate("Production BOM No.", ProductionBOMHeader1."No.");
+        Item1.Modify(true);
+
+        // [GIVEN] Create and refresh Released Production Order for Item1 with Quantity = 1
+        // This will create components: Item2A (qty=1), Item2B (qty=1), and Item3 (qty=2: 1 from 2A + 1 from 2B)
+        LibraryManufacturing.CreateAndRefreshProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, Item1."No.", 1);
+
+        // [WHEN] Calculate Regenerative Plan for Item3
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item3, WorkDate(), CalcDate('<+1M>', WorkDate()));
+
+        // [THEN] No requisition lines should be created for Item3
+        // because the supply (Prod. Order Line qty = 2) equals the demand (Prod. Order Components total qty = 2)
+        RequisitionLine.SetRange("No.", Item3."No.");
+        Assert.IsTrue(RequisitionLine.IsEmpty(), UnexpectedRequisitionLineErr);
+    end;
