+
+    [Test]
+    procedure RolledUpCapacityCostSameForEmptyBOMAndNoBOM()
+    var
+        CompItem: Record Item;
+        ProdItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        EmptyProductionBOMHeader: Record "Production BOM Header";
+        BOMBuffer: Record "BOM Buffer";
+        BOMCostShares: TestPage "BOM Cost Shares";
+        RolledUpCapCostWithEmptyBOM: Decimal;
+        RolledUpCapCostWithNoBOM: Decimal;
+        QtyPer: Decimal;
+    begin
+        // [FEATURE] [Production BOM] [BOM Cost Share]
+        // [SCENARIO] A blank Production BOM on a component should result in the same Rolled-up Capacity Cost as having no Production BOM.
+        Initialize();
+
+        // [GIVEN] Component item "C" with Replenishment System = "Prod. Order" and a routing with capacity costs.
+        LibraryAssembly.CreateItem(CompItem, CompItem."Costing Method"::FIFO, CompItem."Replenishment System"::"Prod. Order", '', '');
+        CompItem.Validate("Unit Cost", LibraryRandom.RandDecInRange(50, 100, 2));
+        CompItem.Modify(true);
+        LibraryAssembly.CreateRouting(CompItem, 1);
+        UpdateRoutingCostValues(CompItem."Routing No.");
+
+        // [GIVEN] Create an empty certified Production BOM (no lines) and assign it to component "C".
+        LibraryManufacturing.CreateProductionBOMHeader(EmptyProductionBOMHeader, CompItem."Base Unit of Measure");
+        LibraryManufacturing.UpdateProductionBOMStatus(EmptyProductionBOMHeader, EmptyProductionBOMHeader.Status::Certified);
+        CompItem.Validate("Production BOM No.", EmptyProductionBOMHeader."No.");
+        CompItem.Modify(true);
+
+        // [GIVEN] Production item "P" with a Production BOM that includes component "C" with Quantity per = 5.
+        QtyPer := LibraryRandom.RandIntInRange(3, 5);
+        LibraryInventory.CreateItem(ProdItem);
+        ProdItem.Validate("Replenishment System", ProdItem."Replenishment System"::"Prod. Order");
+        ProdItem.Modify(true);
+
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ProdItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, CompItem."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+        ProdItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ProdItem.Modify(true);
+
+        // [WHEN] Open "BOM Cost Shares" page for "P" (with component having empty BOM).
+        BOMCostShares.Trap();
+        RunBOMCostSharesPage(ProdItem);
+        BOMCostShares.Expand(true);
+        BOMCostShares.FILTER.SetFilter(Type, Format(BOMBuffer.Type::Item));
+        BOMCostShares.FILTER.SetFilter("No.", CompItem."No.");
+        BOMCostShares.First();
+        RolledUpCapCostWithEmptyBOM := BOMCostShares."Rolled-up Capacity Cost".AsDecimal();
+        BOMCostShares.Close();
+
+        // [GIVEN] Remove the empty Production BOM from component "C" (make Production BOM No. blank).
+        CompItem.Find();
+        CompItem.Validate("Production BOM No.", '');
+        CompItem.Modify(true);
+
+        // [WHEN] Open "BOM Cost Shares" page for "P" again (now component has no BOM).
+        BOMCostShares.Trap();
+        RunBOMCostSharesPage(ProdItem);
+        BOMCostShares.Expand(true);
+        BOMCostShares.FILTER.SetFilter(Type, Format(BOMBuffer.Type::Item));
+        BOMCostShares.FILTER.SetFilter("No.", CompItem."No.");
+        BOMCostShares.First();
+        RolledUpCapCostWithNoBOM := BOMCostShares."Rolled-up Capacity Cost".AsDecimal();
+        BOMCostShares.Close();
+
+        // [THEN] "Rolled-up Capacity Cost" for component "C" is the same in both cases.
+        Assert.AreEqual(
+          RolledUpCapCostWithNoBOM, RolledUpCapCostWithEmptyBOM,
+          StrSubstNo(IncorrectValueErr, CompItem.TableCaption(), CompItem.FieldCaption("No.")));
+    end;
 }

