+++ b/App/Layers/W1/Tests/ERM/IssuedReminderEmailTests.Codeunit.al
@@ -0,0 +1,135 @@
+codeunit 134980 "Issued Reminder Email Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryERM: Codeunit "Library - ERM";
+        Assert: Codeunit Assert;
+        Any: Codeunit Any;
+        IsInitialized: Boolean;
+
+    local procedure Initialize()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        if IsInitialized then
+            exit;
+
+        if not SalesReceivablesSetup.Get() then
+            SalesReceivablesSetup.Insert();
+
+        SalesReceivablesSetup."Posting Date Check on Posting" := false;
+        SalesReceivablesSetup.Modify();
+        Commit();
+        IsInitialized := true;
+    end;
+
+    [Test]
+    procedure IssuedReminderEmailShouldUseCustomerNoFieldForCustomerLookup()
+    var
+        Customer: Record Customer;
+        ReminderTerms: Record "Reminder Terms";
+        ReminderHeader: Record "Reminder Header";
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        SendEmailMock: Codeunit "Send Email Mock";
+        FieldNameCaptureMock: Codeunit "Reminder Field Name Capture";
+    begin
+        // [FEATURE] [Issued Reminders] [Email]
+        // [SCENARIO] When sending an issued reminder by email, the system should use 'Customer No.' field 
+        // to identify the customer so that the email appears in the customer's sent email history
+        Initialize();
+
+        // [GIVEN] Create reminder term with levels
+        CreateReminderTermsWithLevels(ReminderTerms, '<1M>', Any.IntegerInRange(2, 5));
+
+        // [GIVEN] Create a customer with overdue entries
+        CreateCustomerWithOverdueEntries(Customer, ReminderTerms, 1);
+
+        // [GIVEN] Create and issue reminder for customer
+        CreateAndIssueReminder(ReminderHeader, Customer."No.");
+
+        // [WHEN] Send the issued reminder by email
+        IssuedReminderHeader.SetRange("Pre-Assigned No.", ReminderHeader."No.");
+        IssuedReminderHeader.FindFirst();
+
+        BindSubscription(SendEmailMock);
+        BindSubscription(FieldNameCaptureMock);
+        SendEmailMock.AddSupportedScenario(Enum::"Email Scenario"::Reminder);
+        IssuedReminderHeader.PrintRecords(false, true, false);
+        UnbindSubscription(FieldNameCaptureMock);
+        UnbindSubscription(SendEmailMock);
+
+        // [THEN] The system should use 'Customer No.' field for Issued Reminder Header to identify the customer
+        Assert.AreEqual(Database::"Issued Reminder Header", FieldNameCaptureMock.GetDocumentTableIdCaptured(),
+            'Document table ID should be Issued Reminder Header');
+        Assert.AreEqual('Customer No.', FieldNameCaptureMock.GetCustomerFieldNameUsed(),
+            'Field name should be ''Customer No.'' for Issued Reminder Header, not ''Sell-to Customer No.''');
+    end;
+
+    local procedure CreateReminderTermsWithLevels(var ReminderTerms: Record "Reminder Terms"; DueDatePeriod: Text; NumberOfLevels: Integer)
+    var
+        ReminderLevel: Record "Reminder Level";
+        i: Integer;
+    begin
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        for i := 1 to NumberOfLevels do begin
+            LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+            Evaluate(ReminderLevel."Due Date Calculation", DueDatePeriod);
+            ReminderLevel.Modify();
+        end;
+    end;
+
+    local procedure CreateCustomerWithOverdueEntries(var Customer: Record Customer; var ReminderTerms: Record "Reminder Terms"; NumberOfEntries: Integer)
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ReminderLevel: Record "Reminder Level";
+        Item: Record Item;
+        PostingDate: Date;
+        I: Integer;
+    begin
+        ReminderLevel.SetRange("Reminder Terms Code", ReminderTerms.Code);
+        ReminderLevel.FindFirst();
+
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("Reminder Terms Code", ReminderTerms.Code);
+        Customer."E-Mail" := 'test@example.com';
+        Customer.Modify(true);
+
+        PostingDate := WorkDate() + (WorkDate() - CalcDate(ReminderLevel."Due Date Calculation", WorkDate()));
+        PostingDate := CalcDate('<-5M>', PostingDate);
+
+        for I := 1 to NumberOfEntries do begin
+            LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+            SalesHeader.Validate("Posting Date", PostingDate);
+            SalesHeader.Modify(true);
+
+            LibraryInventory.CreateItem(Item);
+            LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", 1);
+            SalesLine.Validate("Unit Price", Any.DecimalInRange(100, 500, 2));
+            SalesLine.Modify(true);
+
+            LibrarySales.PostSalesDocument(SalesHeader, true, true);
+        end;
+    end;
+
+    local procedure CreateAndIssueReminder(var ReminderHeader: Record "Reminder Header"; CustomerNo: Code[20])
+    var
+        SuggestReminderLines: Report "Suggest Reminder Lines";
+    begin
+        LibraryERM.CreateReminderHeader(ReminderHeader);
+        ReminderHeader.Validate("Customer No.", CustomerNo);
+        ReminderHeader.Modify(true);
+
+        ReminderHeader.SetRange("No.", ReminderHeader."No.");
+        SuggestReminderLines.SetTableView(ReminderHeader);
+        SuggestReminderLines.UseRequestPage(false);
+        SuggestReminderLines.Run();
+
+        ReminderHeader.SetRecFilter();
+        Report.RunModal(Report::"Issue Reminders", false, true, ReminderHeader);
+    end;
+}
