+    [Test]
+    [TransactionModel(TransactionModel::AutoRollback)]
+    procedure TestLowLevelCodeCalculatedWhenProdBOMSetOnSKU()
+    var
+        ManufacturingSetup: Record "Manufacturing Setup";
+        Location: Record Location;
+        MainItem: Record Item;
+        ComponentItem: Record Item;
+        StockkeepingUnit: Record "Stockkeeping Unit";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        // [SCENARIO] When a Production BOM is assigned to a Stockkeeping Unit, the low-level codes should be calculated dynamically
+        // so that regenerative planning can plan both the main item and its components in a single run.
+        // This addresses the issue where components were not planned on the first run of Calculate Regenerative Plan
+        // when Stockkeeping Units were set up for items.
+
+        // [GIVEN] Clean environment
+        DeleteDemoDataEntities();
+        StockkeepingUnit.DeleteAll();
+
+        // [GIVEN] Manufacturing Setup with Dynamic Low-Level Code enabled
+        ManufacturingSetup.Get();
+        ManufacturingSetup."Dynamic Low-Level Code" := true;
+        ManufacturingSetup.Modify();
+
+        // [GIVEN] A location for the SKU
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+
+        // [GIVEN] A component item with Purchase replenishment
+        CreateItem(ComponentItem);
+        ComponentItem."Replenishment System" := ComponentItem."Replenishment System"::Purchase;
+        ComponentItem.Modify();
+
+        // [GIVEN] A main item with Prod. Order replenishment
+        CreateItem(MainItem);
+        MainItem."Replenishment System" := MainItem."Replenishment System"::"Prod. Order";
+        MainItem.Modify();
+
+        // [GIVEN] A certified Production BOM with the component
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, MainItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader, ProductionBOMLine, '', "Production BOM Line Type"::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, "BOM Status"::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] A Stockkeeping Unit for the main item at the location
+        LibraryInventory.CreateStockkeepingUnitForLocationAndVariant(StockkeepingUnit, Location.Code, MainItem."No.", '');
+
+        // [WHEN] The Production BOM is set on the SKU (not directly on the Item)
+        StockkeepingUnit.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        StockkeepingUnit.Modify(true);
+
+        // [THEN] The main item should have the correct low-level code (0 as it's the top-level item in the BOM hierarchy)
+        MainItem.Find('=');
+        Assert.AreEqual(0, MainItem."Low-Level Code", 'Main item should have low-level code 0');
