+    [Test]
+    procedure TrialBalanceBufferClearsDebitCreditWhenValueSignChanges()
+    var
+        TrialBalanceBuffer: Record "EXR Trial Balance Buffer";
+    begin
+        // [SCENARIO] When dimension breakdown results are calculated, reusing the buffer with a different value sign
+        // should clear the opposite Debit/Credit fields to avoid repeated values in Excel reports.
+        // [GIVEN] A Trial Balance Buffer record with a positive Net Change (Debit)
+        TrialBalanceBuffer.Init();
+        TrialBalanceBuffer."G/L Account No." := 'TEST';
+        TrialBalanceBuffer.Validate("Net Change", 100);
+        TrialBalanceBuffer.Validate(Balance, 200);
+        TrialBalanceBuffer.Validate("Last Period Net", 50);
+        TrialBalanceBuffer.Validate("Last Period Bal.", 150);
+        TrialBalanceBuffer.Validate("Net Change (ACY)", 100);
+        TrialBalanceBuffer.Validate("Balance (ACY)", 200);
+        TrialBalanceBuffer.Validate("Last Period Net (ACY)", 50);
+        TrialBalanceBuffer.Validate("Last Period Bal. (ACY)", 150);
+
+        // [THEN] Debit values should be set, Credit values should be zero
+        Assert.AreEqual(100, TrialBalanceBuffer."Net Change (Debit)", 'Net Change Debit should be set');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit)", 'Net Change Credit should be zero');
+        Assert.AreEqual(200, TrialBalanceBuffer."Balance (Debit)", 'Balance Debit should be set');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Credit)", 'Balance Credit should be zero');
+        Assert.AreEqual(50, TrialBalanceBuffer."Last Period Net (Debit)", 'Last Period Net Debit should be set');
+        Assert.AreEqual(0, TrialBalanceBuffer."Last Period Net (Credit)", 'Last Period Net Credit should be zero');
+        Assert.AreEqual(150, TrialBalanceBuffer."Last Period Bal. (Debit)", 'Last Period Bal Debit should be set');
+        Assert.AreEqual(0, TrialBalanceBuffer."Last Period Bal. (Credit)", 'Last Period Bal Credit should be zero');
+
+        // [WHEN] The same buffer is reused with negative values (Credit)
+        TrialBalanceBuffer.Validate("Net Change", -100);
+        TrialBalanceBuffer.Validate(Balance, -200);
+        TrialBalanceBuffer.Validate("Last Period Net", -50);
+        TrialBalanceBuffer.Validate("Last Period Bal.", -150);
+        TrialBalanceBuffer.Validate("Net Change (ACY)", -100);
+        TrialBalanceBuffer.Validate("Balance (ACY)", -200);
+        TrialBalanceBuffer.Validate("Last Period Net (ACY)", -50);
+        TrialBalanceBuffer.Validate("Last Period Bal. (ACY)", -150);
+
+        // [THEN] Credit values should be set, Debit values should be cleared (not retain old values)
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Debit)", 'Net Change Debit should be cleared after sign change');
+        Assert.AreEqual(100, TrialBalanceBuffer."Net Change (Credit)", 'Net Change Credit should be set');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Debit)", 'Balance Debit should be cleared after sign change');
+        Assert.AreEqual(200, TrialBalanceBuffer."Balance (Credit)", 'Balance Credit should be set');
+        Assert.AreEqual(0, TrialBalanceBuffer."Last Period Net (Debit)", 'Last Period Net Debit should be cleared after sign change');
+        Assert.AreEqual(50, TrialBalanceBuffer."Last Period Net (Credit)", 'Last Period Net Credit should be set');
+        Assert.AreEqual(0, TrialBalanceBuffer."Last Period Bal. (Debit)", 'Last Period Bal Debit should be cleared after sign change');
+        Assert.AreEqual(150, TrialBalanceBuffer."Last Period Bal. (Credit)", 'Last Period Bal Credit should be set');
+
+        // [WHEN] Changing back to positive values
+        TrialBalanceBuffer.Validate("Net Change", 300);
+        TrialBalanceBuffer.Validate(Balance, 400);
+
+        // [THEN] Debit values should be set, Credit values should be cleared
+        Assert.AreEqual(300, TrialBalanceBuffer."Net Change (Debit)", 'Net Change Debit should be set after reverting to positive');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit)", 'Net Change Credit should be cleared after reverting to positive');
+        Assert.AreEqual(400, TrialBalanceBuffer."Balance (Debit)", 'Balance Debit should be set after reverting to positive');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Credit)", 'Balance Credit should be cleared after reverting to positive');
+    end;
