+        // [SCENARIO] When recalculating an item in requisition worksheet with no planning results, 
+        // no surplus reservation entries should be created for the purchase line with item tracking.
+
+        // [GIVEN] Initialize and set planning end date
+        Initialize();
+        PlanningEndDate := CalcDate('<+2M>', WorkDate());
+        OriginalQuantity := LibraryRandom.RandIntInRange(100, 200);
+        IncreasedQuantity := OriginalQuantity + LibraryRandom.RandIntInRange(50, 100);
+
+        // [GIVEN] Create Item Tracking Code with Lot Purchase Inbound Tracking enabled
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, false);
+        ItemTrackingCode.Validate("Lot Purchase Inbound Tracking", true);
+        ItemTrackingCode.Modify(true);
+
+        // [GIVEN] Create Item with Lot-for-Lot reordering policy and lot tracking
+        LibraryInventory.CreateTrackedItem(Item, LibraryUtility.GetGlobalNoSeriesCode(), '', ItemTrackingCode.Code);
+        Item.Validate("Replenishment System", Item."Replenishment System"::Purchase);
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::"Lot-for-Lot");
+        Item.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        Item.Modify(true);
+
+        // [GIVEN] Create Sales Order for the item
+        CreateSalesOrder(SalesHeader, SalesLine, Item."No.", OriginalQuantity);
+
+        // [GIVEN] Calculate Plan for Requisition Worksheet
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), PlanningEndDate);
+
+        // [GIVEN] Modify requisition line quantity and set Planning Flexibility = None
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate(Quantity, IncreasedQuantity);
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        RequisitionLine.Modify(true);
+
+        // [GIVEN] Assign Lot Tracking to the requisition line
+        RequisitionLine.OpenItemTrackingLines();
+
+        // [GIVEN] Accept Action Message and Carry Out
+        AcceptActionMessage(Item."No.");
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        // [GIVEN] Verify purchase order was created and get initial reservation entry count
+        SelectPurchaseLine(PurchaseLine, Item."No.");
+        PurchaseLine.TestField(Quantity, IncreasedQuantity);
+
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type".AsInteger());
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", PurchaseLine."Line No.");
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        InitialPurchLineReservEntryCount := ReservationEntry.Count();
+
+        // [WHEN] Calculate Plan for Requisition Worksheet again (should have no planning results due to Planning Flexibility = None)
+        RequisitionWkshName.FindFirst();
+        LibraryPlanning.CalculatePlanForReqWksh(
+          Item, RequisitionWkshName."Worksheet Template Name", RequisitionWkshName.Name, WorkDate(), PlanningEndDate);
+
+        // [THEN] No new requisition line should be created for the item (due to Planning Flexibility = None)
+        FilterOnRequisitionLine(RequisitionLine, Item."No.");
+        Assert.IsTrue(RequisitionLine.IsEmpty, StrSubstNo(RequisitionLineMustNotExistTxt, Item."No."));
+
+        // [THEN] No new surplus reservation entries should be created for the purchase line
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type".AsInteger());
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", PurchaseLine."Line No.");
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        Assert.AreEqual(InitialPurchLineReservEntryCount, ReservationEntry.Count(), 'Reservation entry count should not change after replanning');
+
+        // [THEN] No new Prospect status entries should exist (bug created wrong Surplus from Prospect entries)
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Prospect);
+        Assert.IsTrue(ReservationEntry.IsEmpty, 'No Prospect reservation entries should exist for the purchase line');
+    end;
+
