+    [Test]
+    [HandlerFunctions('GetShipmentLinesHandler')]
+    [Scope('OnPrem')]
+    procedure CustomerTotalAmountLCYNotTripleCountedForShipmentGetLines()
+    var
+        Customer: Record Customer;
+        Item: Record Item;
+        SalesHeaderOrder: Record "Sales Header";
+        SalesLineOrder: Record "Sales Line";
+        SalesHeaderInvoice: Record "Sales Header";
+        SalesLineInvoice: Record "Sales Line";
+        SalesShipmentLine: Record "Sales Shipment Line";
+        ExpectedTotalAmountLCY: Decimal;
+    begin
+        // [SCENARIO] Customer Total Amount LCY should not be triple-counted when a Sales Order is shipped
+        // and a Sales Invoice uses Get Shipment Lines prior to posting
+        Initialize();
+
+        // [GIVEN] Create a new Customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Create an Item with a unit price
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 1000, 2));
+        Item.Modify(true);
+
+        // [GIVEN] Create and post shipment only for a Sales Order
+        LibrarySales.CreateSalesHeader(SalesHeaderOrder, SalesHeaderOrder."Document Type"::Order, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLineOrder, SalesHeaderOrder, SalesLineOrder.Type::Item, Item."No.", LibraryRandom.RandIntInRange(1, 10));
+        ExpectedTotalAmountLCY := SalesLineOrder."Outstanding Amount (LCY)";
+        LibrarySales.PostSalesDocument(SalesHeaderOrder, true, false); // Ship only
+
+        // [GIVEN] Create a Sales Invoice and use Get Shipment Lines to bring in the shipped items
+        LibrarySales.CreateSalesHeader(SalesHeaderInvoice, SalesHeaderInvoice."Document Type"::Invoice, Customer."No.");
+        SalesLineInvoice."Document Type" := SalesHeaderInvoice."Document Type";
+        SalesLineInvoice."Document No." := SalesHeaderInvoice."No.";
+
+        SalesShipmentLine.SetRange("Sell-to Customer No.", Customer."No.");
+        SalesShipmentLine.FindFirst();
+        LibraryVariableStorage.Enqueue(SalesShipmentLine."Document No.");
+        Commit();
+        LibrarySales.GetShipmentLines(SalesLineInvoice);
+
+        // [GIVEN] Release the Sales Invoice but do not post
+        LibrarySales.ReleaseSalesDocument(SalesHeaderInvoice);
+
+        // [WHEN] Calculate Customer's Total Amount LCY
+        Customer.CalcFields("Balance (LCY)", "Outstanding Orders (LCY)", "Shipped Not Invoiced (LCY)", "Outstanding Invoices (LCY)");
+
+        // [THEN] The Total Amount LCY should equal the expected amount (not tripled)
+        // Without the fix, the amount would be counted three times:
+        // 1. From "Outstanding Orders (LCY)" - still contains amount for unposted order
+        // 2. From "Shipped Not Invoiced (LCY)" - contains amount for shipped but not invoiced goods
+        // 3. From "Outstanding Invoices (LCY)" - contains amount for invoice lines created from Get Shipment Lines
+        // Plus SalesOutstandingAmountFromShipment adds it again
+        Assert.AreEqual(ExpectedTotalAmountLCY, Customer.GetTotalAmountLCY(), 'Total Amount LCY should not be tripled for shipment with Get Shipment Lines');
+    end;
+
